// @ts-nocheck
import React, { useState, useEffect, useCallback } from 'react';
import {
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Avatar,
  Menu,
  MenuItem,
  Box,
  Breadcrumbs,
  Link,
  Badge,
  ListItemIcon,
  ListItemText,
  alpha,
  InputBase,
  Paper,
  Button,
  Tooltip,
  Divider,
  CircularProgress,
} from '@mui/material';
import {
  Logout,
  NavigateNext as NavigateNextIcon,
  Notifications as NotificationsIcon,
  Search as SearchIcon,
  List as ListIcon,
  DoneAll as DoneAllIcon,
  Cake as CakeIcon,
  NotificationImportant as NotificationImportantIcon,
} from '@mui/icons-material';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { apiService } from '../../services/api';

interface BellNotification {
  id: number;
  templateName: string;
  subject: string;
  content: string;
  sentDate: string;
  sentTime: string;
  channel: string;
  status: string;
  isRead: boolean;
}

const Header: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const [notificationAnchor, setNotificationAnchor] = useState<null | HTMLElement>(null);
  const [notifications, setNotifications] = useState<BellNotification[]>([]);
  const [loadingNotifications, setLoadingNotifications] = useState(false);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const fetchNotifications = useCallback(async () => {
    try {
      setLoadingNotifications(true);
      const response = await apiService.getBellNotifications();
      if (response.success) {
        setNotifications(response.data || []);
      }
    } catch (error) {
      console.error('Error fetching bell notifications:', error);
    } finally {
      setLoadingNotifications(false);
    }
  }, []);

  useEffect(() => {
    fetchNotifications();
    // Poll for new notifications every 30 seconds
    const interval = setInterval(fetchNotifications, 30000);
    return () => clearInterval(interval);
  }, [fetchNotifications]);

  const getRoleDisplayName = () => {
    const role = user?.role || 'employee';
    return role.charAt(0).toUpperCase() + role.slice(1);
  };

  const handleMenu = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleNotificationClick = (event: React.MouseEvent<HTMLElement>) => {
    setNotificationAnchor(event.currentTarget);
  };

  const handleNotificationClose = () => {
    setNotificationAnchor(null);
  };

  const handleMarkAsRead = async (id: number) => {
    await apiService.markBellNotificationRead(id);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
  };

  const handleMarkAllRead = async () => {
    await apiService.markAllBellNotificationsRead();
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const handleLogout = () => {
    localStorage.removeItem('authToken');
    navigate('/login');
    handleClose();
  };

  const getBreadcrumbs = () => {
    const pathnames = location.pathname.split('/').filter((x) => x);
    const breadcrumbs = [
      <Link
        key="home"
        color="inherit"
        href="/dashboard"
        onClick={(e) => {
          e.preventDefault();
          navigate('/dashboard');
        }}
        sx={{
          textDecoration: 'none',
          '&:hover': { textDecoration: 'underline' },
        }}
      >
        Home
      </Link>
    ];

    pathnames.forEach((value, index) => {
      const to = `/${pathnames.slice(0, index + 1).join('/')}`;
      const isLast = index === pathnames.length - 1;

      let displayName = value.charAt(0).toUpperCase() + value.slice(1);

      if (value === 'manpower-types') displayName = 'Manpower Types';
      if (value === 'work-locations') displayName = 'Work Locations';
      if (value === 'payment-modes') displayName = 'Payment Modes';
      if (value === 'document-types') displayName = 'Document Types';
      if (value === 'new') displayName = 'New';
      if (value === 'edit') displayName = 'Edit';

      if (isLast) {
        breadcrumbs.push(
          <Typography key={to} color="text.primary" sx={{ fontWeight: 600 }}>
            {displayName}
          </Typography>
        );
      } else {
        breadcrumbs.push(
          <Link
            key={to}
            color="inherit"
            href={to}
            onClick={(e) => {
              e.preventDefault();
              navigate(to);
            }}
            sx={{
              textDecoration: 'none',
              '&:hover': { textDecoration: 'underline' },
            }}
          >
            {displayName}
          </Link>
        );
      }
    });

    return breadcrumbs;
  };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/dashboard') return 'Dashboard';
    if (path === '/employees') return 'Employee Management';
    if (path === '/employees/new') return 'Add New Employee';
    if (path.startsWith('/employees/edit/')) return 'Edit Employee';
    if (path === '/performance/kpi-list') return 'KPI List';
    if (path === '/performance/kpi/create') return 'Create KPI';
    if (path.startsWith('/performance/kpi/edit/')) return 'Edit KPI';
    if (path === '/performance/manager-review') return 'KPI Review';
    if (path === '/masters/manpower-types') return 'Manpower Types';
    if (path === '/masters/departments') return 'Departments';
    if (path === '/masters/designations') return 'Designations';
    if (path === '/masters/shifts') return 'Shifts';
    if (path === '/masters/work-locations') return 'Work Locations';
    if (path === '/masters/banks') return 'Banks';
    if (path === '/masters/payment-modes') return 'Payment Modes';
    if (path === '/masters/qualifications') return 'Qualifications';
    if (path === '/masters/document-types') return 'Document Types';
    return 'HRMS';
  };

  return (
    <AppBar
      position="static"
      elevation={0}
      sx={{
        backgroundColor: 'white',
        borderBottom: '1px solid rgba(0, 0, 0, 0.08)',
        boxShadow: '0 2px 8px rgba(0, 0, 0, 0.04)',
      }}
    >
      <Toolbar sx={{ px: 3, py: 2 }}>
        <Box sx={{ flexGrow: 1 }}>
          <Typography
            variant="h5"
            component="div"
            sx={{
              color: 'text.primary',
              mb: 0.5,
              fontWeight: 700,
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              backgroundClip: 'text',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
            }}
          >
            {getPageTitle()}
          </Typography>
          <Breadcrumbs
            separator={<NavigateNextIcon fontSize="small" sx={{ color: 'text.secondary' }} />}
            aria-label="breadcrumb"
            sx={{ fontSize: '0.875rem' }}
          >
            {getBreadcrumbs()}
          </Breadcrumbs>
        </Box>

        {/* Search Bar */}
        <Paper
          component="form"
          sx={{
            p: '4px 12px',
            display: 'flex',
            alignItems: 'center',
            width: 300,
            mr: 2,
            backgroundColor: alpha('#667eea', 0.05),
            border: '1px solid',
            borderColor: alpha('#667eea', 0.1),
            borderRadius: 2,
            transition: 'all 0.2s',
            '&:hover': {
              borderColor: alpha('#667eea', 0.3),
              backgroundColor: alpha('#667eea', 0.08),
            },
            '&:focus-within': {
              borderColor: '#667eea',
              backgroundColor: 'white',
              boxShadow: '0 0 0 3px rgba(102, 126, 234, 0.1)',
            },
          }}
        >
          <InputBase
            sx={{ ml: 1, flex: 1, fontSize: '0.875rem' }}
            placeholder="Search..."
            inputProps={{ 'aria-label': 'search' }}
          />
          <IconButton type="button" sx={{ p: '8px' }} aria-label="search">
            <SearchIcon fontSize="small" />
          </IconButton>
        </Paper>

        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          {/* KPI List Button for Admin */}
          {(user?.role === 'admin' || user?.role === 'manager') && (
            <Button
              variant="outlined"
              startIcon={<ListIcon />}
              onClick={() => navigate('/performance/kpi-list')}
              sx={{
                mr: 1,
                textTransform: 'none',
                borderColor: alpha('#667eea', 0.3),
                color: '#667eea',
                '&:hover': {
                  borderColor: '#667eea',
                  backgroundColor: alpha('#667eea', 0.08),
                },
              }}
            >
              KPI List
            </Button>
          )}

          {/* Notifications */}
          <IconButton
            onClick={handleNotificationClick}
            sx={{
              position: 'relative',
              '&:hover': {
                backgroundColor: alpha('#667eea', 0.08),
              },
            }}
          >
            <Badge badgeContent={unreadCount} color="error">
              <NotificationsIcon sx={{ color: 'text.secondary' }} />
            </Badge>
          </IconButton>

          <Menu
            anchorEl={notificationAnchor}
            open={Boolean(notificationAnchor)}
            onClose={handleNotificationClose}
            PaperProps={{
              sx: {
                width: 380,
                maxHeight: 500,
                mt: 1.5,
                borderRadius: 2,
                boxShadow: '0 8px 32px rgba(0, 0, 0, 0.16)',
                overflow: 'hidden',
              },
            }}
            transformOrigin={{ horizontal: 'right', vertical: 'top' }}
            anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
          >
            {/* Header */}
            <Box sx={{
              p: 2,
              borderBottom: '1px solid rgba(0, 0, 0, 0.08)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              background: 'linear-gradient(135deg, #667eea08, #764ba208)',
            }}>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <NotificationsIcon sx={{ color: '#667eea', fontSize: 20 }} />
                <Typography variant="h6" sx={{ fontWeight: 700, fontSize: '1rem' }}>
                  Notifications
                </Typography>
                {unreadCount > 0 && (
                  <Box sx={{
                    backgroundColor: '#ef4444',
                    color: 'white',
                    borderRadius: '10px',
                    px: 0.8,
                    py: 0.1,
                    fontSize: '0.7rem',
                    fontWeight: 700,
                    minWidth: 20,
                    textAlign: 'center',
                  }}>
                    {unreadCount}
                  </Box>
                )}
              </Box>
              {unreadCount > 0 && (
                <Tooltip title="Mark all as read">
                  <IconButton size="small" onClick={handleMarkAllRead} sx={{ color: '#667eea' }}>
                    <DoneAllIcon fontSize="small" />
                  </IconButton>
                </Tooltip>
              )}
            </Box>

            {/* Notification List */}
            <Box sx={{ overflowY: 'auto', maxHeight: 400 }}>
              {loadingNotifications ? (
                <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
                  <CircularProgress size={24} />
                </Box>
              ) : notifications.length === 0 ? (
                <Box sx={{ p: 4, textAlign: 'center' }}>
                  <NotificationsIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
                  <Typography variant="body2" color="text.secondary">
                    No notifications yet
                  </Typography>
                  <Typography variant="caption" color="text.disabled">
                    Reminders sent from admin will appear here
                  </Typography>
                </Box>
              ) : (
                notifications.map((notification, index) => (
                  <Box key={notification.id}>
                    <MenuItem
                      onClick={() => {
                        handleMarkAsRead(notification.id);
                        handleNotificationClose();
                      }}
                      sx={{
                        py: 1.5,
                        px: 2,
                        alignItems: 'flex-start',
                        backgroundColor: notification.isRead ? 'transparent' : alpha('#667eea', 0.04),
                        borderLeft: notification.isRead ? '3px solid transparent' : '3px solid #667eea',
                        '&:hover': {
                          backgroundColor: alpha('#667eea', 0.08),
                        },
                      }}
                    >
                      <Box sx={{ display: 'flex', gap: 1.5, width: '100%' }}>
                        <Avatar sx={{
                          width: 36, height: 36, flexShrink: 0,
                          background: notification.templateName?.includes('Birthday')
                            ? 'linear-gradient(135deg, #f093fb, #f5576c)'
                            : 'linear-gradient(135deg, #667eea, #764ba2)',
                          fontSize: '1rem'
                        }}>
                          {notification.templateName?.includes('Birthday') ? '🎂' : '🔔'}
                        </Avatar>
                        <Box sx={{ flex: 1, minWidth: 0 }}>
                          <Typography
                            variant="body2"
                            sx={{
                              fontWeight: notification.isRead ? 400 : 700,
                              color: 'text.primary',
                              fontSize: '0.8rem',
                              lineHeight: 1.3,
                              mb: 0.3,
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap',
                            }}
                          >
                            {notification.subject}
                          </Typography>
                          <Typography
                            variant="caption"
                            color="text.secondary"
                            sx={{
                              display: 'block',
                              fontSize: '0.72rem',
                              lineHeight: 1.4,
                              overflow: 'hidden',
                              textOverflow: 'ellipsis',
                              whiteSpace: 'nowrap',
                            }}
                          >
                            {notification.content}
                          </Typography>
                          <Typography variant="caption" sx={{ color: '#667eea', fontSize: '0.68rem', mt: 0.3, display: 'block' }}>
                            {notification.sentDate} {notification.sentTime}
                          </Typography>
                        </Box>
                        {!notification.isRead && (
                          <Box sx={{
                            width: 8, height: 8, borderRadius: '50%',
                            backgroundColor: '#667eea',
                            mt: 0.5, flexShrink: 0,
                          }} />
                        )}
                      </Box>
                    </MenuItem>
                    {index < notifications.length - 1 && <Divider sx={{ my: 0 }} />}
                  </Box>
                ))
              )}
            </Box>
          </Menu>


          {/* User Profile */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mr: 1 }}>
            <Box sx={{ textAlign: 'right', display: { xs: 'none', sm: 'block' } }}>
              <Typography variant="body2" sx={{ fontWeight: 600, color: 'text.primary' }}>
                {user?.name || 'User'}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                {getRoleDisplayName()}
              </Typography>
            </Box>
            <IconButton
              size="large"
              onClick={handleMenu}
              sx={{
                p: 0,
                '&:hover': {
                  transform: 'scale(1.05)',
                  transition: 'transform 0.2s',
                },
              }}
            >
              <Avatar
                sx={{
                  width: 40,
                  height: 40,
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  border: '2px solid white',
                  boxShadow: '0 2px 8px rgba(0, 0, 0, 0.1)',
                }}
              >
                {user?.name?.charAt(0)?.toUpperCase() || 'U'}
              </Avatar>
            </IconButton>
          </Box>

          <Menu
            id="menu-appbar"
            anchorEl={anchorEl}
            open={Boolean(anchorEl)}
            onClose={handleClose}
            PaperProps={{
              sx: {
                width: 220,
                mt: 1.5,
                borderRadius: 2,
                boxShadow: '0 8px 24px rgba(0, 0, 0, 0.12)',
              },
            }}
            transformOrigin={{ horizontal: 'right', vertical: 'top' }}
            anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
          >
            <Box sx={{ p: 2, borderBottom: '1px solid rgba(0, 0, 0, 0.08)' }}>
              <Typography variant="body2" sx={{ fontWeight: 600 }}>
                {user?.name || 'User'}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                {user?.email || user?.username || ''}
              </Typography>
            </Box>
            <MenuItem onClick={handleLogout} sx={{ py: 1.5, color: 'error.main' }}>
              <ListItemIcon>
                <Logout fontSize="small" sx={{ color: 'error.main' }} />
              </ListItemIcon>
              <ListItemText>Logout</ListItemText>
            </MenuItem>
          </Menu>
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Header;

import React, { useState } from 'react';
import { Button, CircularProgress, Tooltip } from '@mui/material';
import { Download, PictureAsPdf } from '@mui/icons-material';
import { apiService } from '../services/api';

interface PDFDownloadButtonProps {
  moduleType: 'KPI' | 'ASSET' | 'LEAVE' | 'EXPENSE';
  recordId: number;
  fileName?: string;
  variant?: 'contained' | 'outlined' | 'text';
  size?: 'small' | 'medium' | 'large';
  color?: 'primary' | 'secondary' | 'error' | 'info' | 'success' | 'warning';
  fullWidth?: boolean;
  disabled?: boolean;
}

const PDFDownloadButton: React.FC<PDFDownloadButtonProps> = ({
  moduleType,
  recordId,
  fileName,
  variant = 'outlined',
  size = 'medium',
  color = 'primary',
  fullWidth = false,
  disabled = false,
}) => {
  const [loading, setLoading] = useState(false);

  const handleDownload = async () => {
    setLoading(true);
    try {
      let blob: Blob;
      let defaultFileName: string;

      switch (moduleType) {
        case 'KPI':
          blob = await apiService.downloadKPIPDF(recordId);
          defaultFileName = `KPI_Report_${recordId}.pdf`;
          break;
        case 'ASSET':
          blob = await apiService.downloadAssetPDF(recordId);
          defaultFileName = `Asset_Report_${recordId}.pdf`;
          break;
        case 'LEAVE':
          blob = await apiService.downloadEmployeeFormPDF('LEAVE', recordId);
          defaultFileName = `Leave_Request_${recordId}.pdf`;
          break;
        case 'EXPENSE':
          blob = await apiService.downloadEmployeeFormPDF('EXPENSE', recordId);
          defaultFileName = `Expense_Request_${recordId}.pdf`;
          break;
        default:
          throw new Error(`Unsupported module type: ${moduleType}`);
      }

      // Create download link
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName || defaultFileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (error: any) {
      console.error('Error downloading PDF:', error);
      const errorMessage = error?.message || 'Failed to download PDF. Please try again.';
      alert(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Tooltip title={`Download ${moduleType} Report as PDF`}>
      <span>
        <Button
          variant={variant}
          size={size}
          color={color}
          fullWidth={fullWidth}
          disabled={disabled || loading}
          startIcon={loading ? <CircularProgress size={16} /> : <PictureAsPdf />}
          onClick={handleDownload}
        >
          {loading ? 'Generating...' : 'Download PDF'}
        </Button>
      </span>
    </Tooltip>
  );
};

export default PDFDownloadButton;

import React, { useState } from 'react';
import {
  Box,
  TextField,
  Button,
  Paper,
  Typography,
  Avatar,
  Divider,
} from '@mui/material';
import { Send as SendIcon, Person as PersonIcon } from '@mui/icons-material';

export interface Comment {
  id: number;
  comment: string;
  user_name?: string;
  user_email?: string;
  created_at: string;
}

interface CommentBoxProps {
  comments: Comment[];
  onAddComment: (comment: string) => Promise<void>;
  currentUserName?: string;
  currentUserEmail?: string;
}

export const CommentBox: React.FC<CommentBoxProps> = ({
  comments,
  onAddComment,
  currentUserName,
  currentUserEmail,
}) => {
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async () => {
    if (!newComment.trim()) return;

    setIsSubmitting(true);
    try {
      await onAddComment(newComment.trim());
      setNewComment('');
    } catch (error) {
      console.error('Error adding comment:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const getInitials = (name?: string, email?: string) => {
    if (name) {
      return name
        .split(' ')
        .map((n) => n[0])
        .join('')
        .toUpperCase()
        .slice(0, 2);
    }
    if (email) {
      return email[0].toUpperCase();
    }
    return 'U';
  };

  return (
    <Box>
      <Typography variant="h6" gutterBottom>
        Comments ({comments.length})
      </Typography>

      {/* Add Comment Form */}
      <Paper sx={{ p: 2, mb: 3 }}>
        <TextField
          fullWidth
          multiline
          rows={3}
          placeholder="Add a comment..."
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          sx={{ mb: 2 }}
        />
        <Box display="flex" justifyContent="flex-end">
          <Button
            variant="contained"
            startIcon={<SendIcon />}
            onClick={handleSubmit}
            disabled={!newComment.trim() || isSubmitting}
          >
            {isSubmitting ? 'Posting...' : 'Post Comment'}
          </Button>
        </Box>
      </Paper>

      {/* Comments List */}
      <Box>
        {comments.length === 0 ? (
          <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', py: 4 }}>
            No comments yet. Be the first to comment!
          </Typography>
        ) : (
          comments.map((comment, index) => (
            <Box key={comment.id}>
              <Box display="flex" gap={2} mb={2}>
                <Avatar sx={{ bgcolor: 'primary.main' }}>
                  {getInitials(comment.user_name, comment.user_email)}
                </Avatar>
                <Box flex={1}>
                  <Box display="flex" justifyContent="space-between" alignItems="center" mb={0.5}>
                    <Typography variant="subtitle2" fontWeight={600}>
                      {comment.user_name || comment.user_email || 'Unknown User'}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      {new Date(comment.created_at).toLocaleString()}
                    </Typography>
                  </Box>
                  <Typography variant="body2" color="text.secondary">
                    {comment.comment}
                  </Typography>
                </Box>
              </Box>
              {index < comments.length - 1 && <Divider sx={{ my: 2 }} />}
            </Box>
          ))
        )}
      </Box>
    </Box>
  );
};

import React, { useState, useEffect } from 'react';
import {
  Box,
  TextField,
  Button,
  Grid as MuiGrid,
  GridProps,
  Paper,
  Typography,
} from '@mui/material';
import { Save as SaveIcon, Cancel as CancelIcon } from '@mui/icons-material';
import { ResponsiveDropdown } from '../Common';

// Create a Grid component that supports both old and new API
const Grid = (props: GridProps & { 
  size?: { xs?: number | boolean; sm?: number | boolean; md?: number | boolean; lg?: number | boolean };
  item?: boolean;
  xs?: number | boolean;
  sm?: number | boolean;
  md?: number | boolean;
  lg?: number | boolean;
}) => {
  // If using new size prop, convert to old props for compatibility
  if (props.size) {
    const { size, ...rest } = props;
    return <MuiGrid component="div" {...rest} xs={size.xs} sm={size.sm} md={size.md} lg={size.lg} />;
  }
  // If using old item prop, use component="div"
  if (props.item) {
    return <MuiGrid component="div" {...props} />;
  }
  return <MuiGrid {...props} />;
};

export interface User {
  id: number;
  name: string;
  email: string;
  role: string;
}

interface CreateTaskFormProps {
  onSubmit: (taskData: {
    title: string;
    description?: string;
    assignedTo: number;
    priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
    deadline?: string;
  }) => Promise<void>;
  onCancel: () => void;
  users?: User[];
  initialData?: {
    title?: string;
    description?: string;
    assignedTo?: number;
    priority?: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
    deadline?: string;
  };
  mode?: 'create' | 'edit';
}

export const CreateTaskForm: React.FC<CreateTaskFormProps> = ({
  onSubmit,
  onCancel,
  users = [],
  initialData,
  mode = 'create',
}) => {
  const [formData, setFormData] = useState({
    title: initialData?.title || '',
    description: initialData?.description || '',
    assignedTo: initialData?.assignedTo || '',
    priority: initialData?.priority || 'MEDIUM',
    deadline: initialData?.deadline || '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validate = () => {
    const newErrors: Record<string, string> = {};

    if (!formData.title.trim()) {
      newErrors.title = 'Title is required';
    }

    if (!formData.assignedTo) {
      newErrors.assignedTo = 'Please assign the task to someone';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) {
      return;
    }

    setIsSubmitting(true);
    try {
      await onSubmit({
        title: formData.title.trim(),
        description: formData.description.trim() || undefined,
        assignedTo: parseInt(formData.assignedTo as string),
        priority: formData.priority as 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT',
        deadline: formData.deadline || undefined,
      });
    } catch (error) {
      console.error('Error submitting task:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Paper sx={{ p: 3 }}>
      <Typography variant="h6" gutterBottom>
        {mode === 'create' ? 'Create New Task' : 'Edit Task'}
      </Typography>

      <form onSubmit={handleSubmit}>
        <Grid container spacing={3}>
          <Grid item xs={12}>
            <TextField
              fullWidth
              label="Task Title"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              error={!!errors.title}
              helperText={errors.title}
              required
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              fullWidth
              multiline
              rows={4}
              label="Description"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <ResponsiveDropdown
              label="Assign To"
              value={formData.assignedTo}
              onChange={(e) => setFormData({ ...formData, assignedTo: e.target.value })}
              options={users.map((user) => ({
                value: user.id,
                label: `${user.name} (${user.email}) - ${user.role}`,
              }))}
              required
              error={!!errors.assignedTo}
              helperText={errors.assignedTo}
              placeholder="Select an employee"
            />
          </Grid>

          <Grid item xs={12} md={6}>
            <ResponsiveDropdown
              label="Priority"
              value={formData.priority}
              onChange={(e) => setFormData({ ...formData, priority: e.target.value as any })}
              options={[
                { value: 'LOW', label: 'Low' },
                { value: 'MEDIUM', label: 'Medium' },
                { value: 'HIGH', label: 'High' },
                { value: 'URGENT', label: 'Urgent' },
              ]}
              placeholder="Select priority"
            />
          </Grid>

          <Grid item xs={12}>
            <TextField
              fullWidth
              type="date"
              label="Deadline"
              value={formData.deadline}
              onChange={(e) => setFormData({ ...formData, deadline: e.target.value })}
              InputLabelProps={{
                shrink: true,
              }}
            />
          </Grid>

          <Grid item xs={12}>
            <Box display="flex" justifyContent="flex-end" gap={2}>
              <Button
                variant="outlined"
                startIcon={<CancelIcon />}
                onClick={onCancel}
                disabled={isSubmitting}
              >
                Cancel
              </Button>
              <Button
                type="submit"
                variant="contained"
                startIcon={<SaveIcon />}
                disabled={isSubmitting}
              >
                {isSubmitting ? 'Saving...' : mode === 'create' ? 'Create Task' : 'Update Task'}
              </Button>
            </Box>
          </Grid>
        </Grid>
      </form>
    </Paper>
  );
};

import React from 'react';
import {
  Card,
  CardContent,
  Typography,
  Chip,
  Box,
  IconButton,
  Tooltip,
} from '@mui/material';
import {
  Assignment as TaskIcon,
  AccessTime as TimeIcon,
  Person as PersonIcon,
  ArrowForward as ArrowIcon,
} from '@mui/icons-material';
import { TaskStatusBadge } from './TaskStatusBadge';
import { PriorityLabel } from './PriorityLabel';
import { DeadlineChip } from './DeadlineChip';

export interface Task {
  id: number;
  title: string;
  description?: string;
  status: 'PENDING' | 'IN_PROGRESS' | 'COMPLETED' | 'CLOSED' | 'CANCELLED';
  priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'URGENT';
  deadline?: string;
  assigned_to_name?: string;
  created_by_name?: string;
  created_at?: string;
  updated_at?: string;
}

interface TaskCardProps {
  task: Task;
  onClick?: () => void;
  showAssignee?: boolean;
  showCreator?: boolean;
}

export const TaskCard: React.FC<TaskCardProps> = ({
  task,
  onClick,
  showAssignee = true,
  showCreator = false,
}) => {
  const isOverdue = !!(task.deadline && new Date(task.deadline) < new Date() && task.status !== 'COMPLETED' && task.status !== 'CLOSED');

  return (
    <Card
      sx={{
        mb: 2,
        cursor: onClick ? 'pointer' : 'default',
        transition: 'all 0.2s',
        '&:hover': onClick ? {
          boxShadow: 4,
          transform: 'translateY(-2px)',
        } : {},
        borderLeft: `4px solid ${
          task.priority === 'URGENT' ? '#f44336' :
          task.priority === 'HIGH' ? '#ff9800' :
          task.priority === 'MEDIUM' ? '#2196f3' :
          '#4caf50'
        }`,
      }}
      onClick={onClick}
    >
      <CardContent>
        <Box display="flex" justifyContent="space-between" alignItems="flex-start" mb={1}>
          <Box flex={1}>
            <Typography variant="h6" component="div" sx={{ fontWeight: 600, mb: 1 }}>
              {task.title}
            </Typography>
            {task.description && (
              <Typography
                variant="body2"
                color="text.secondary"
                sx={{
                  mb: 1.5,
                  display: '-webkit-box',
                  WebkitLineClamp: 2,
                  WebkitBoxOrient: 'vertical',
                  overflow: 'hidden',
                }}
              >
                {task.description}
              </Typography>
            )}
          </Box>
          {onClick && (
            <IconButton size="small" sx={{ ml: 1 }}>
              <ArrowIcon />
            </IconButton>
          )}
        </Box>

        <Box display="flex" flexWrap="wrap" gap={1} alignItems="center" mb={1}>
          <TaskStatusBadge status={task.status} />
          <PriorityLabel priority={task.priority} />
          {task.deadline && (
            <DeadlineChip deadline={task.deadline} isOverdue={isOverdue} />
          )}
        </Box>

        <Box display="flex" flexWrap="wrap" gap={2} alignItems="center" mt={1.5}>
          {showAssignee && task.assigned_to_name && (
            <Box display="flex" alignItems="center" gap={0.5}>
              <PersonIcon fontSize="small" color="action" />
              <Typography variant="caption" color="text.secondary">
                {task.assigned_to_name}
              </Typography>
            </Box>
          )}
          {showCreator && task.created_by_name && (
            <Box display="flex" alignItems="center" gap={0.5}>
              <TaskIcon fontSize="small" color="action" />
              <Typography variant="caption" color="text.secondary">
                Created by: {task.created_by_name}
              </Typography>
            </Box>
          )}
          {task.created_at && (
            <Box display="flex" alignItems="center" gap={0.5}>
              <TimeIcon fontSize="small" color="action" />
              <Typography variant="caption" color="text.secondary">
                {new Date(task.created_at).toLocaleDateString()}
              </Typography>
            </Box>
          )}
        </Box>
      </CardContent>
    </Card>
  );
};

