                  />
                </Box>
              </Grid>
            </>
          )}
        </Grid>
      </Paper>
      {/* Preview Dialog */}
      <Dialog open={previewDialog} onClose={() => setPreviewDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle>
          Letter Preview - {selectedTemplate?.name}
