        <DialogContent>
          <Paper variant="outlined" sx={{ p: 3, mb: 2, backgroundColor: '#fff' }}>
            {(selectedTemplate?.type === 'OFFER' || selectedTemplate?.name.toLowerCase().includes('offer')) && (
              <Box sx={{ mb: 3, display: 'flex', justifyContent: 'center', borderBottom: '1px solid #eee', pb: 2 }}>
                <img
                  src={`${process.env.REACT_APP_API_URL || 'http://localhost:8080'}/uploads/assets/offer_header.png`}
                  alt="Letter Header"
                  style={{ maxWidth: '100%', height: 'auto', maxHeight: '100px' }}
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = 'none';
                  }}
                />
              </Box>
            )}
            <Typography variant="body1" sx={{ whiteSpace: 'pre-line', fontFamily: 'monospace' }}>
              {generatedContent}
            </Typography>
          </Paper>

          <Grid container spacing={2}>
            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Email Subject"
                value={letterData.subject || selectedTemplate?.name}
                onChange={(e) => setLetterData(prev => ({ ...prev, subject: e.target.value }))}
              />
            </Grid>
            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Recipient Email"
                value={letterData.recipientEmail || selectedEmployee?.email}
                onChange={(e) => setLetterData(prev => ({ ...prev, recipientEmail: e.target.value }))}
              />
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setPreviewDialog(false)}>Close</Button>
          <Button
            startIcon={<SaveIcon />}
            onClick={saveLetter}
            disabled={loading}
          >
            Save Letter
          </Button>
          <Button
            startIcon={<DownloadIcon />}
            onClick={downloadLetter}
            variant="outlined"
          >
            Download
          </Button>
          <Button
            startIcon={<SendIcon />}
            onClick={sendEmail}
            variant="contained"
            disabled={loading}
          >
            Send Email
          </Button>
        </DialogActions>
      </Dialog>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
      >
        <Alert
          severity={snackbar.severity}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
          variant="filled"
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

