const OfferLetterForm: React.FC = () => {
    const navigate = useNavigate();
    const [activeStep, setActiveStep] = useState(0);
    const [loading, setLoading] = useState(false);
    const [snackbar, setSnackbar] = useState({
        open: false,
        message: '',
        severity: 'success' as 'success' | 'error' | 'warning'
    });
    const [generatedId, setGeneratedId] = useState<number | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const [formData, setFormData] = useState<OfferLetterData>({
        candidateName: '',
        address: '',
        date: new Date().toISOString().split('T')[0],
        designation: '',
        location: '',
        joiningDate: '',
        calculationBasis: 'Old Basis',
        esicCovered: 'No',
        basicSalary: 0,
        hra: 0,
        variableDearnessAllowance: 0,
        otherAllowances: 0,
        performanceBonus: 0,
        leaveEncashment: 0,
        advanceBonus: 0,
        grossSalary: 0,
        emyPF: 0,
        emyESIC: 0,
        pTax: 0,
        lwfEmployee: 0,
        totalDeductions: 0,
        netAmount: 0,
        emrPF: 0,
        emrAdminCharges: 0,
        emrESIC: 0,
        lwfEmployer: 0,
        gratuity: 0,
        totalEMRContribution: 0,
        monthlySalary: 0,
        monthlyCTC: 0,
        yearlyCTC: 0,
        acceptanceCandidateName: '',
        aadhaarNumber: '',
        acceptanceDate: new Date().toISOString().split('T')[0],
        candidateSignature: null,
        probation: 'You shall be on probation for a period of twelve months from the date of your joining. This period may be extended further at the discretion of the management. Your appointment will be considered confirmed only after the confirmation letter by management.',
    });



    // Auto-calculate all salary components based on Gross and Basis
    React.useEffect(() => {
        const gross = Number(formData.grossSalary) || 0;

        let basic = 0;
        let hra = 0;
        let other = 0;
        let bonus = 0;

        if (formData.calculationBasis === 'Old Basis') {
            // Old Basis: Basic is Gross / 2.0833
            basic = Math.round(gross / 2.0833);
            hra = Math.round(basic * 0.5);
            bonus = Math.round(basic * 0.0833 * 10) / 10;
            other = Math.max(0, gross - (basic + hra + bonus));
        } else {
            // New Government Rule: Basic = Gross * 0.57242
            basic = Math.round(gross * 0.57242);
            hra = Math.round(basic * 0.5);
            bonus = Math.round(basic * 0.0833 * 10) / 10;
            other = Math.max(0, gross - (basic + hra + bonus));
        }

        // Deductions
        const emyPF = Math.round(basic * 0.12);
        const emyESIC = formData.esicCovered === 'Yes' && gross <= 21000 ? Math.ceil(gross * 0.0075) : 0;
        const pTax = gross > 15000 ? 200 : 0; // Standard slab example
        const lwfEmployee = formData.esicCovered === 'Yes' ? 10 : 0; // Standard nominal value
        const totalDeductions = emyPF + emyESIC + pTax + lwfEmployee;
        const netAmount = Math.round(gross - totalDeductions);

        // Employer Contributions
        const emrPF = emyPF; // 12%
        const emrAdmin = Math.round(basic * 0.01);
        const emrESIC = formData.esicCovered === 'Yes' && gross <= 21000 ? Math.ceil(gross * 0.0325) : 0;
        const lwfEmployer = formData.esicCovered === 'Yes' ? 20 : 0;
        const gratuity = Math.floor(basic * 0.0481); // Use floor to match image (721/1058)
        const totalEMR = emrPF + emrAdmin + emrESIC + lwfEmployer + gratuity;

        const monthlyCTC = gross + totalEMR;
        const yearlyCTC = Math.round(monthlyCTC * 12);

        setFormData(prev => ({
            ...prev,
            basicSalary: basic,
            hra: hra,
            otherAllowances: other,
            performanceBonus: bonus,
            emyPF,
            emyESIC,
            pTax,
            lwfEmployee,
            totalDeductions,
            netAmount,
            emrPF,
            emrAdminCharges: emrAdmin,
            emrESIC,
            lwfEmployer,
            gratuity,
            totalEMRContribution: totalEMR,
            monthlySalary: gross,
            monthlyCTC: monthlyCTC,
            yearlyCTC: yearlyCTC,
            // Auto-populate acceptance candidate name if empty
            acceptanceCandidateName: prev.acceptanceCandidateName || prev.candidateName,
        }));
    }, [formData.grossSalary, formData.calculationBasis, formData.esicCovered, formData.candidateName]);

    const handleInputChange = (field: keyof OfferLetterData, value: any) => {
        setFormData(prev => ({
            ...prev,
            [field]: value,
        }));
    };

    const handleSignatureUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setFormData(prev => ({
                    ...prev,
                    candidateSignature: reader.result as string,
                }));
            };
            reader.readAsDataURL(file);
        }
    };

    const handleClearSignature = () => {
        setFormData(prev => ({
            ...prev,
            candidateSignature: null,
        }));
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const validateStep = (step: number): boolean => {
        switch (step) {
            case 0:
                return !!(
                    formData.candidateName &&
                    formData.address &&
                    formData.date &&
                    formData.designation &&
                    formData.location &&
                    formData.joiningDate &&
                    formData.probation
                );
            case 1:
                return !!(
                    formData.grossSalary > 0 &&
                    formData.calculationBasis
                );
            case 2:
                return !!(
                    formData.acceptanceCandidateName &&
                    formData.aadhaarNumber &&
                    formData.acceptanceDate
                );
            default:
                return false;
        }
    };

    const handleNext = () => {
        if (!validateStep(activeStep)) {
            setSnackbar({
                open: true,
                message: 'Please fill all required fields',
                severity: 'warning'
            });
            return;
        }
        setActiveStep((prevActiveStep) => prevActiveStep + 1);
    };

    const handleBack = () => {
        setActiveStep((prevActiveStep) => prevActiveStep - 1);
    };

    const handleGeneratePDF = async () => {
        if (!validateStep(2)) {
            setSnackbar({
                open: true,
                message: 'Please fill all required fields',
                severity: 'warning'
            });
            return;
        }

        try {
            setLoading(true);

            // Call backend API to generate PDF
            const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
            const response = await fetch(`${apiUrl}/api/offer-letters/generate`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(formData),
            });

            if (!response.ok) {
                throw new Error('Failed to generate PDF');
            }

            // Download the PDF
            const blob = await response.blob();
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `Offer_Letter_${formData.candidateName.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`;
            link.click();
            window.URL.revokeObjectURL(url);

            setSnackbar({
                open: true,
                message: 'Offer letter generated successfully!',
                severity: 'success'
            });

            // Capture the generated ID from header
            const offerLetterId = response.headers.get('X-Offer-Letter-Id');
            if (offerLetterId) {
                setGeneratedId(parseInt(offerLetterId));
            }

        } catch (error) {
            console.error('Error generating PDF:', error);
            setSnackbar({
                open: true,
                message: 'Error generating PDF. Please try again.',
                severity: 'error'
            });
        } finally {
            setLoading(false);
        }
    };

    const handleSendToEmployee = async () => {
        if (!generatedId) return;

        try {
            setLoading(true);
            const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
            const response = await fetch(`${apiUrl}/api/offer-letters/${generatedId}/status`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ status: 'Sent' }),
            });

            if (!response.ok) {
                throw new Error('Failed to send offer letter');
            }

            setSnackbar({
                open: true,
                message: 'Offer letter sent to employee successfully!',
                severity: 'success'
            });

            // Reset form after a delay
            setTimeout(() => {
                navigate('/documents/offer-letter');
            }, 2000);

        } catch (error) {
            console.error('Error sending offer letter:', error);
            setSnackbar({
                open: true,
                message: 'Error sending offer letter. Please try again.',
                severity: 'error'
            });
        } finally {
            setLoading(false);
        }
    };

    const renderStepContent = (step: number) => {
        switch (step) {
            case 0:
                return (
                    <Grid container spacing={3}>
                        <Grid item xs={12}>
                            <TextField
                                fullWidth
                                required
                                label="Candidate Name"
                                value={formData.candidateName}
                                onChange={(e) => handleInputChange('candidateName', e.target.value)}
                                placeholder="Enter candidate's full name"
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <TextField
                                fullWidth
                                required
                                label="Address"
                                multiline
                                rows={3}
                                value={formData.address}
                                onChange={(e) => handleInputChange('address', e.target.value)}
                                placeholder="Enter complete address"
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                type="date"
                                label="Date"
                                value={formData.date}
                                onChange={(e) => handleInputChange('date', e.target.value)}
                                InputLabelProps={{ shrink: true }}
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                label="Designation"
                                value={formData.designation}
                                onChange={(e) => handleInputChange('designation', e.target.value)}
                                placeholder="e.g., Asst. Manager - Business Development"
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                label="Location"
                                value={formData.location}
                                onChange={(e) => handleInputChange('location', e.target.value)}
                                placeholder="e.g., New Delhi"
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                type="date"
                                label="Joining Date"
                                value={formData.joiningDate}
                                onChange={(e) => handleInputChange('joiningDate', e.target.value)}
                                InputLabelProps={{ shrink: true }}
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <TextField
                                fullWidth
                                required
                                label="PROBATION & BOND"
                                multiline
                                rows={4}
                                value={formData.probation}
                                onChange={(e) => handleInputChange('probation', e.target.value)}
                                placeholder="Enter probation and bond details"
                            />
                        </Grid>
                    </Grid>
                );

            case 1:
                return (
                    <Grid container spacing={3}>
                        <Grid item xs={12}>
                            <Alert severity="info" sx={{ mb: 2 }}>
                                Select the calculation basis and enter the monthly gross salary. Components will be calculated automatically.
                            </Alert>
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <TextField
                                fullWidth
                                select
                                label="Salary Calculation Basis"
                                value={formData.calculationBasis}
                                onChange={(e) => handleInputChange('calculationBasis', e.target.value)}
                                SelectProps={{ native: true }}
                            >
                                <option value="Old Basis">Old Basis</option>
                                <option value="New Government Rule">New Government Rule</option>
                            </TextField>
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <TextField
                                fullWidth
                                select
                                label="ESIC Covered"
                                value={formData.esicCovered}
                                onChange={(e) => handleInputChange('esicCovered', e.target.value)}
                                SelectProps={{ native: true }}
                            >
                                <option value="No">No</option>
                                <option value="Yes">Yes</option>
                            </TextField>
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <TextField
                                fullWidth
                                required
                                type="number"
                                label="Monthly Gross Salary"
                                value={formData.grossSalary || ''}
                                onChange={(e) => handleInputChange('grossSalary', parseFloat(e.target.value) || 0)}
                                InputProps={{
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Basic Salary"
                                value={formData.basicSalary || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="HRA"
                                value={formData.hra || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Bonus (8.33%)"
                                value={formData.performanceBonus || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Other Allowances"
                                value={formData.otherAllowances || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Employee PF"
                                value={formData.emyPF || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Employee ESIC"
                                value={formData.emyESIC || '0'}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="P.Tax"
                                value={formData.pTax || '0'}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="LWF (EE)"
                                value={formData.lwfEmployee || '0'}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                label="Net Take Home (Approx)"
                                value={formData.netAmount || ''}
                                variant="filled"
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                label="Gratuity (4.81%)"
                                value={formData.gratuity || ''}
                                InputProps={{
                                    readOnly: true,
                                    startAdornment: <InputAdornment position="start">₹</InputAdornment>,
                                }}
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <Divider sx={{ my: 2 }} />
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <Card variant="outlined" sx={{ bgcolor: 'info.light', color: 'info.contrastText' }}>
                                <CardContent>
                                    <Typography variant="subtitle2" gutterBottom>
                                        Monthly Gross Salary
                                    </Typography>
                                    <Typography variant="h5" fontWeight="bold">
                                        ₹ {formData.grossSalary.toLocaleString('en-IN')}
                                    </Typography>
                                </CardContent>
                            </Card>
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <Card variant="outlined" sx={{ bgcolor: 'primary.light', color: 'primary.contrastText' }}>
                                <CardContent>
                                    <Typography variant="subtitle2" gutterBottom>
                                        Monthly CTC (Gross + EMR)
                                    </Typography>
                                    <Typography variant="h5" fontWeight="bold">
                                        ₹ {formData.monthlyCTC.toLocaleString('en-IN')}
                                    </Typography>
                                </CardContent>
                            </Card>
                        </Grid>
                        <Grid item xs={12} md={4}>
                            <Card variant="outlined" sx={{ bgcolor: 'success.light', color: 'success.contrastText' }}>
                                <CardContent>
                                    <Typography variant="subtitle2" gutterBottom>
                                        Yearly CTC
                                    </Typography>
                                    <Typography variant="h5" fontWeight="bold">
                                        ₹ {formData.yearlyCTC.toLocaleString('en-IN')}
                                    </Typography>
                                </CardContent>
                            </Card>
                        </Grid>
                    </Grid>
                );

            case 2:
                return (
                    <Grid container spacing={3}>
                        <Grid item xs={12}>
                            <Alert severity="info" sx={{ mb: 2 }}>
                                This section captures the candidate's acceptance of the offer letter.
                            </Alert>
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                label="Candidate Name (Acceptance)"
                                value={formData.acceptanceCandidateName}
                                onChange={(e) => handleInputChange('acceptanceCandidateName', e.target.value)}
                                placeholder="Enter candidate's name for acceptance"
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                label="Aadhaar Number"
                                value={formData.aadhaarNumber}
                                onChange={(e) => handleInputChange('aadhaarNumber', e.target.value)}
                                placeholder="Enter 12-digit Aadhaar number"
                                inputProps={{ maxLength: 12 }}
                            />
                        </Grid>
                        <Grid item xs={12} md={6}>
                            <TextField
                                fullWidth
                                required
                                type="date"
                                label="Acceptance Date"
                                value={formData.acceptanceDate}
                                onChange={(e) => handleInputChange('acceptanceDate', e.target.value)}
                                InputLabelProps={{ shrink: true }}
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <Box sx={{ mt: 2, p: 2, border: '1px solid #e0e0e0', borderRadius: 1, bgcolor: '#f5f7ff' }}>
                                <Typography variant="subtitle2" color="primary" gutterBottom fontWeight="bold" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                                    Authorised Signatory
                                    <Box component="span" sx={{ fontSize: '0.75rem', fontWeight: 'normal', px: 1, py: 0.25, bgcolor: 'primary.main', color: 'white', borderRadius: 4 }}>Fixed</Box>
                                </Typography>
                                <img
                                    src={`${process.env.REACT_APP_API_URL || 'http://localhost:8080'}/uploads/assets/authorised_signatory.png`}
                                    alt="Authorised Signatory"
                                    style={{ maxWidth: '150px', maxHeight: '60px', display: 'block', marginTop: '8px' }}
                                    onError={(e) => {
                                        (e.target as HTMLImageElement).style.display = 'none';
                                    }}
                                />
                                <Typography variant="caption" color="text.secondary">
                                    Cogent Logistics Pvt Ltd
                                </Typography>
                            </Box>
                        </Grid>
                        <Grid item xs={12}>
                            <Divider sx={{ my: 2 }} />
                            <Typography variant="subtitle1" gutterBottom fontWeight="bold">
                                Candidate Signature
                            </Typography>
                            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                                Upload the candidate's signature image (PNG, JPG, or JPEG)
                            </Typography>
                            <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                                <input
                                    ref={fileInputRef}
                                    type="file"
                                    accept="image/png,image/jpeg,image/jpg"
                                    onChange={handleSignatureUpload}
                                    style={{ display: 'none' }}
                                    id="signature-upload"
                                />
                                <label htmlFor="signature-upload">
                                    <Button
                                        variant="outlined"
                                        component="span"
                                        startIcon={<UploadIcon />}
                                    >
                                        Upload Signature
                                    </Button>
                                </label>
                                {formData.candidateSignature && (
                                    <IconButton
                                        color="error"
                                        onClick={handleClearSignature}
                                        size="small"
                                    >
                                        <ClearIcon />
                                    </IconButton>
                                )}
                            </Box>
                            {formData.candidateSignature && (
                                <Box sx={{ mt: 2, p: 2, border: '1px solid #ddd', borderRadius: 1, bgcolor: '#f9f9f9' }}>
                                    <Typography variant="caption" color="text.secondary" gutterBottom>
                                        Signature Preview:
                                    </Typography>
                                    <img
                                        src={formData.candidateSignature}
                                        alt="Candidate Signature"
                                        style={{ maxWidth: '200px', maxHeight: '100px', display: 'block', marginTop: '8px' }}
                                    />
                                </Box>
                            )}
                        </Grid>
                    </Grid>
                );

            default:
                return null;
        }
    };

    return (
        <Box>
            <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold', mb: 1 }}>
                Offer Letter Generation
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                Generate professional offer letters with automated PDF generation
            </Typography>

            <Paper elevation={2} sx={{ p: 3 }}>
                {/* Header Image Preview */}
                <Box sx={{ mb: 4, display: 'flex', justifyContent: 'center', borderBottom: '1px solid #eee', pb: 2 }}>
                    <img
                        src={`${process.env.REACT_APP_API_URL || 'http://localhost:8080'}/uploads/assets/offer_header.png`}
                        alt="Offer Letter Header"
                        style={{ maxWidth: '100%', height: 'auto', maxHeight: '120px' }}
                        onError={(e) => {
                            // Hide if image doesn't exist
                            (e.target as HTMLImageElement).style.display = 'none';
                        }}
                    />
                </Box>

                <Stepper activeStep={activeStep} sx={{ mb: 4 }}>
                    {steps.map((label) => (
                        <Step key={label}>
                            <StepLabel>{label}</StepLabel>
                        </Step>
                    ))}
                </Stepper>

                <Box sx={{ minHeight: '400px' }}>
                    {renderStepContent(activeStep)}
                </Box>

                <Divider sx={{ my: 3 }} />

                <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                    <Button
                        disabled={activeStep === 0 || !!generatedId}
                        onClick={handleBack}
                        startIcon={<BackIcon />}
                        variant="outlined"
                    >
                        Back
                    </Button>

                    <Box sx={{ display: 'flex', gap: 2 }}>
                        {activeStep === steps.length - 1 ? (
                            <>
                                {generatedId ? (
                                    <Button
                                        variant="contained"
                                        color="success"
                                        onClick={handleSendToEmployee}
                                        disabled={loading}
                                        startIcon={<SendIcon />}
                                        sx={{
                                            background: 'linear-gradient(135deg, #43a047 0%, #2e7d32 100%)',
                                            '&:hover': {
                                                background: 'linear-gradient(135deg, #388e3c 0%, #1b5e20 100%)',
                                            },
                                        }}
                                    >
                                        {loading ? 'Sending...' : 'Send to Employee Dashboard'}
                                    </Button>
                                ) : (
                                    <Button
                                        variant="contained"
                                        onClick={handleGeneratePDF}
                                        disabled={loading}
                                        startIcon={<DownloadIcon />}
                                        size="large"
                                        sx={{
                                            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                                            '&:hover': {
                                                background: 'linear-gradient(135deg, #5568d3 0%, #6a3f8f 100%)',
                                            },
                                        }}
                                    >
                                        {loading ? 'Generating PDF...' : 'Generate & Download PDF'}
                                    </Button>
                                )}
                            </>
                        ) : (
                            <Button
                                variant="contained"
                                onClick={handleNext}
                                endIcon={<NextIcon />}
                            >
                                Next
                            </Button>
                        )}
                    </Box>
                </Box>
            </Paper>

            <Snackbar
                open={snackbar.open}
                autoHideDuration={6000}
                onClose={() => setSnackbar({ ...snackbar, open: false })}
                anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
            >
                <Alert
                    severity={snackbar.severity}
                    onClose={() => setSnackbar({ ...snackbar, open: false })}
                    variant="filled"
                >
                    {snackbar.message}
                </Alert>
            </Snackbar>
        </Box>
    );
};

export default OfferLetterForm;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
    Box,
    Paper,
    Typography,
    Button,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Chip,
    IconButton,
    Tooltip,
    TextField,
    InputAdornment,
    Menu,
    MenuItem,
    ListItemIcon,
    CircularProgress
} from '@mui/material';
import {
    Add as AddIcon,
    Search as SearchIcon,
    Visibility as ViewIcon,
    Edit as EditIcon,
    Send as SendIcon,
    MoreVert as MoreVertIcon,
    Download as DownloadIcon,
    Delete as DeleteIcon
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogContentText,
    DialogActions,
} from '@mui/material';

interface OfferLetter {
    id: number;
    candidate_name: string;
    designation: string;
    generated_date: string;
    status: 'Draft' | 'Sent' | 'Viewed' | 'Accepted';
    pdf_path: string;
    employee_id: number | null;
    monthly_ctc: number;
    yearly_ctc: number;
}

const OfferLetterList: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [offerLetters, setOfferLetters] = useState<OfferLetter[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
    const [selectedId, setSelectedId] = useState<number | null>(null);
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    const [idToDelete, setIdToDelete] = useState<number | null>(null);
    const [sendDialogOpen, setSendDialogOpen] = useState(false);
    const [selectedLetter, setSelectedLetter] = useState<OfferLetter | null>(null);
    const [selectedEmployeeId, setSelectedEmployeeId] = useState<number | string>('');
    const [employees, setEmployees] = useState<any[]>([]);

    // Fetch offer letters
    const fetchOfferLetters = async () => {
        try {
            setLoading(true);
            const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
            const response = await axios.get(`${apiUrl}/api/offer-letters/list`);
            if (response.data.success) {
                setOfferLetters(response.data.data);
            }
        } catch (error) {
            console.error('Error fetching offer letters:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchEmployees = async () => {
        try {
            const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
            const response = await axios.get(`${apiUrl}/api/employees`);
            if (response.data.success) {
                setEmployees(response.data.data.content || []);
            }
        } catch (error) {
            console.error('Error fetching employees:', error);
        }
    };

    useEffect(() => {
        fetchOfferLetters();
        fetchEmployees();
    }, []);

    const handleMenuOpen = (event: React.MouseEvent<HTMLElement>, id: number) => {
        setAnchorEl(event.currentTarget);
        setSelectedId(id);
    };

    const handleMenuClose = () => {
        setAnchorEl(null);
        setSelectedId(null);
    };

    const handleView = (path: string) => {
        if (!path) {
            alert('PDF path not available');
            return;
        }
        const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
        const filename = path.split(/[/\\]/).pop();
        if (filename) {
            const pdfUrl = `${apiUrl}/uploads/pdfs/${filename}`;
            window.open(pdfUrl, '_blank');
        } else {
            alert('Invalid PDF path');
        }
        handleMenuClose();
    };

    const handleDeleteClick = (id: number) => {
        setIdToDelete(id);
        setDeleteDialogOpen(true);
    };

    const handleDeleteConfirm = async () => {
        if (idToDelete) {
            try {
                const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
                await axios.delete(`${apiUrl}/api/offer-letters/${idToDelete}`);
                fetchOfferLetters();
            } catch (error) {
                console.error('Error deleting offer letter:', error);
                alert('Failed to delete offer letter');
            }
        }
        setDeleteDialogOpen(false);
        setIdToDelete(null);
    };

    const handleEdit = (id: number) => {
        console.log('Edit clicked for', id);
        handleMenuClose();
    };

    const handleSendClick = (letter: OfferLetter) => {
        setSelectedLetter(letter);
        setSelectedEmployeeId(letter.employee_id || '');
        setSendDialogOpen(true);
    };

    const handleSendConfirm = async () => {
        if (!selectedLetter || !selectedEmployeeId) {
            alert('Please select an employee');
            return;
        }

        try {
            setLoading(true);
            const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8080';
            await axios.put(`${apiUrl}/api/offer-letters/${selectedLetter.id}/status`, {
                status: 'Sent',
                employeeId: selectedEmployeeId
            });
            setSendDialogOpen(false);
            fetchOfferLetters();
        } catch (error) {
            console.error('Error sending offer letter:', error);
            alert('Failed to send offer letter');
        } finally {
            setLoading(false);
        }
    };



    const getStatusColor = (status: string) => {
        switch (status) {
            case 'Draft': return 'default';
            case 'Sent': return 'primary';
            case 'Viewed': return 'info';
            case 'Accepted': return 'success';
            default: return 'default';
        }
    };

    const filteredLetters = offerLetters.filter(letter =>
        letter.candidate_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        letter.designation.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <Box>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold' }}>
                    Offer Letters
                </Typography>
                <Button
                    variant="contained"
                    startIcon={<AddIcon />}
                    onClick={() => navigate('/documents/offer-letter/new')}
                    sx={{
                        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                        color: 'white',
                    }}
                >
                    Generate Offer Letter
                </Button>
            </Box>

            <Paper elevation={2} sx={{ p: 2, mb: 3 }}>
                <TextField
                    fullWidth
                    placeholder="Search by candidate name or designation..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    InputProps={{
                        startAdornment: (
                            <InputAdornment position="start">
                                <SearchIcon color="action" />
                            </InputAdornment>
                        ),
                    }}
                    size="small"
                />
            </Paper>

            <TableContainer component={Paper} elevation={2}>
                <Table>
                    <TableHead sx={{ bgcolor: '#f5f7ff' }}>
                        <TableRow>
                            <TableCell sx={{ fontWeight: 'bold' }}>S.No</TableCell>
                            <TableCell sx={{ fontWeight: 'bold' }}>Employee Name</TableCell>
                            <TableCell sx={{ fontWeight: 'bold' }}>Designation</TableCell>
                            <TableCell sx={{ fontWeight: 'bold' }}>Generated Date</TableCell>
                            <TableCell sx={{ fontWeight: 'bold' }}>Status</TableCell>
                            <TableCell sx={{ fontWeight: 'bold', textAlign: 'center' }}>Actions</TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        {loading ? (
                            <TableRow>
                                <TableCell colSpan={7} align="center" sx={{ py: 3 }}>
                                    <CircularProgress size={30} />
                                </TableCell>
                            </TableRow>
                        ) : filteredLetters.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={7} align="center" sx={{ py: 3 }}>
                                    <Typography color="text.secondary">No offer letters found</Typography>
                                </TableCell>
                            </TableRow>
                        ) : (
                            filteredLetters.map((letter, index) => (
                                <TableRow key={letter.id} hover>
                                    <TableCell>{index + 1}</TableCell>
                                    <TableCell sx={{ minWidth: 200 }}>
                                        <Box>
                                            <Typography variant="body2" sx={{ fontWeight: 600 }}>
                                                {letter.candidate_name}
                                            </Typography>
                                            {letter.employee_id && (
                                                <Typography variant="caption" color="text.secondary">
                                                    Assigned to: {(() => {
                                                        const emp = employees.find(e => e.id === letter.employee_id);
                                                        return emp ? `${emp.firstName} ${emp.lastName} (${emp.employeeId})` : `Employee ID: ${letter.employee_id}`;
                                                    })()}
                                                </Typography>
                                            )}
                                        </Box>
                                    </TableCell>
                                    <TableCell>{letter.designation}</TableCell>
                                    <TableCell>{new Date(letter.generated_date).toLocaleDateString()}</TableCell>
                                    <TableCell>
                                        <Chip
                                            label={letter.status}
                                            color={getStatusColor(letter.status) as any}
                                            size="small"
                                            variant="outlined"
                                            sx={{ fontWeight: 'bold' }}
                                        />
                                    </TableCell>
                                    <TableCell align="center">
                                        <Tooltip title="View">
                                            <IconButton size="small" color="primary" onClick={() => handleView(letter.pdf_path)}>
                                                <ViewIcon />
                                            </IconButton>
                                        </Tooltip>
                                        <Tooltip title="Edit">
                                            <IconButton size="small" color="info" onClick={() => handleEdit(letter.id)}>
                                                <EditIcon />
                                            </IconButton>
                                        </Tooltip>
                                        {(letter.status === 'Draft' || letter.status === 'Sent' || letter.status === 'Viewed') && (
                                            <Tooltip title={letter.status === 'Draft' ? "Send" : "Resend"}>
                                                <IconButton size="small" color="success" onClick={() => handleSendClick(letter)}>
                                                    <SendIcon />
                                                </IconButton>
                                            </Tooltip>
                                        )}
                                        <Tooltip title="Delete">
                                            <IconButton size="small" color="error" onClick={() => handleDeleteClick(letter.id)}>
                                                <DeleteIcon />
                                            </IconButton>
                                        </Tooltip>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </TableContainer>

            {/* Delete Confirmation Dialog */}
            <Dialog
                open={deleteDialogOpen}
                onClose={() => setDeleteDialogOpen(false)}
            >
                <DialogTitle>Confirm Delete</DialogTitle>
                <DialogContent>
                    <DialogContentText>
                        Are you sure you want to delete this offer letter? This action cannot be undone.
                    </DialogContentText>
                </DialogContent>
                <DialogActions>
                    <Button onClick={() => setDeleteDialogOpen(false)}>Cancel</Button>
                    <Button onClick={handleDeleteConfirm} color="error" variant="contained">
                        Delete
                    </Button>
                </DialogActions>
            </Dialog>

            {/* Send Offer Letter Dialog */}
            <Dialog
                open={sendDialogOpen}
                onClose={() => setSendDialogOpen(false)}
                maxWidth="xs"
                fullWidth
            >
                <DialogTitle sx={{ fontWeight: 'bold' }}>
                    {selectedLetter?.status === 'Draft' ? 'Send Offer Letter' : 'Resend Offer Letter'}
                </DialogTitle>
                <DialogContent>
                    <DialogContentText sx={{ mb: 3 }}>
                        Select the employee who should receive the offer letter for <strong>{selectedLetter?.candidate_name}</strong>.
                    </DialogContentText>
                    <TextField
                        select
                        fullWidth
                        label="Select Employee"
                        value={selectedEmployeeId}
                        onChange={(e) => setSelectedEmployeeId(e.target.value)}
                        SelectProps={{ native: true }}
                        InputLabelProps={{ shrink: true }}
                    >
                        <option value="">Choose an employee</option>
                        {employees.map(emp => (
                            <option key={emp.id} value={emp.id}>
                                {emp.firstName} {emp.lastName} ({emp.employeeId})
                            </option>
                        ))}
                    </TextField>
                </DialogContent>
                <DialogActions sx={{ px: 3, pb: 2 }}>
                    <Button onClick={() => setSendDialogOpen(false)} color="inherit">
                        Cancel
                    </Button>
                    <Button
                        onClick={handleSendConfirm}
                        color="success"
                        variant="contained"
                        disabled={!selectedEmployeeId || loading}
                    >
                        {loading ? <CircularProgress size={24} color="inherit" /> : (selectedLetter?.status === 'Draft' ? 'Send Now' : 'Resend Now')}
                    </Button>
                </DialogActions>
            </Dialog>
        </Box>
    );
};

export default OfferLetterList;

import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  Alert,
  Snackbar,
} from '@mui/material';
import {
  Add as AddIcon,
  CloudUpload as UploadIcon,
  Download as DownloadIcon,
  Delete as DeleteIcon,
  Description as DocumentIcon,
} from '@mui/icons-material';
import { useParams } from 'react-router-dom';
import { apiService } from '../../services/api';

import { DocumentType } from '../../services/api';

interface EmployeeDocument {
  id: number;
  documentTypeId: number;
  documentTypeName: string;
  fileName: string;
  filePath: string;
  uploadDate: string;
  isMandatory: boolean;
}

const EmployeeDocuments: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [documents, setDocuments] = useState<EmployeeDocument[]>([]);
  const [documentTypes, setDocumentTypes] = useState<DocumentType[]>([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [formData, setFormData] = useState({
    documentTypeId: '',
    description: '',
  });
  const [snackbar, setSnackbar] = useState<{
    open: boolean;
    message: string;
    severity: 'success' | 'error' | 'warning' | 'info';
  }>({ open: false, message: '', severity: 'success' });

  useEffect(() => {
    if (id) {
      loadDocuments();
      loadDocumentTypes();
    }
  }, [id]);

  const loadDocuments = async () => {
    try {
      setLoading(true);
      // Mock data for now
      setDocuments([
        {
          id: 1,
          documentTypeId: 1,
          documentTypeName: 'Aadhar Card',
          fileName: 'aadhar_card.pdf',
          filePath: '/uploads/documents/aadhar_card.pdf',
          uploadDate: '2023-01-15',
          isMandatory: true,
        },
        {
          id: 2,
          documentTypeId: 2,
          documentTypeName: 'PAN Card',
          fileName: 'pan_card.pdf',
          filePath: '/uploads/documents/pan_card.pdf',
          uploadDate: '2023-01-15',
          isMandatory: true,
        },
      ]);
    } catch (error) {
      console.error('Error loading documents:', error);
      setSnackbar({ open: true, message: 'Failed to load documents', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const loadDocumentTypes = async () => {
    try {
      const response = await apiService.getDocumentTypes();
      setDocumentTypes(response.data || [
        { id: 1, name: 'Aadhar Card', isMandatory: true },
        { id: 2, name: 'PAN Card', isMandatory: true },
        { id: 3, name: 'Passport', isMandatory: false },
        { id: 4, name: 'Driving License', isMandatory: false },
        { id: 5, name: 'Educational Certificate', isMandatory: false },
        { id: 6, name: 'Experience Certificate', isMandatory: false },
      ]);
    } catch (error) {
      console.error('Error loading document types:', error);
      setDocumentTypes([
        { id: 1, name: 'Aadhar Card', isMandatory: true },
        { id: 2, name: 'PAN Card', isMandatory: true },
        { id: 3, name: 'Passport', isMandatory: false },
      ]);
    }
  };

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      // Validate file type
      const allowedTypes = ['application/pdf', 'image/jpeg', 'image/png', 'image/jpg'];
      if (!allowedTypes.includes(file.type)) {
        setSnackbar({ open: true, message: 'Please select a PDF or image file', severity: 'error' });
        return;
      }

      // Validate file size (5MB max)
      if (file.size > 5 * 1024 * 1024) {
        setSnackbar({ open: true, message: 'File size should be less than 5MB', severity: 'error' });
        return;
      }

      setSelectedFile(file);
    }
  };

  const handleUpload = async () => {
    const docTypeId = formData.documentTypeId ? parseInt(formData.documentTypeId, 10) : 0;
    if (!selectedFile || !docTypeId) {
      setSnackbar({ open: true, message: 'Please select a file and document type', severity: 'error' });
      return;
    }

    try {
      const uploadFormData = new FormData();
      uploadFormData.append('file', selectedFile);
      uploadFormData.append('documentTypeId', String(docTypeId));
      uploadFormData.append('description', formData.description);

      // Mock upload success
      const newDocument: EmployeeDocument = {
        id: Date.now(),
        documentTypeId: docTypeId,
        documentTypeName: documentTypes.find(dt => dt.id === docTypeId)?.name || '',
        fileName: selectedFile.name,
        filePath: `/uploads/documents/${selectedFile.name}`,
        uploadDate: new Date().toISOString().split('T')[0],
        isMandatory: documentTypes.find(dt => dt.id === docTypeId)?.isMandatory || false,
      };

      setDocuments(prev => [...prev, newDocument]);
      setSnackbar({ open: true, message: 'Document uploaded successfully', severity: 'success' });
      setOpen(false);
      setSelectedFile(null);
      setFormData({ documentTypeId: '', description: '' });
    } catch (error) {
      console.error('Error uploading document:', error);
      setSnackbar({ open: true, message: 'Failed to upload document', severity: 'error' });
    }
  };

  const handleDownload = (document: EmployeeDocument) => {
    // Mock download
    setSnackbar({ open: true, message: `Downloading ${document.fileName}`, severity: 'info' });
  };

  const handleDelete = async (documentId: number) => {
    if (window.confirm('Are you sure you want to delete this document?')) {
      try {
        setDocuments(prev => prev.filter(doc => doc.id !== documentId));
        setSnackbar({ open: true, message: 'Document deleted successfully', severity: 'success' });
      } catch (error) {
        console.error('Error deleting document:', error);
        setSnackbar({ open: true, message: 'Failed to delete document', severity: 'error' });
      }
    }
  };

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <DocumentIcon sx={{ fontSize: 32, color: 'primary.main' }} />
          <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold' }}>
            Employee Documents
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => setOpen(true)}
          sx={{ borderRadius: 2 }}
        >
          Upload Document
        </Button>
      </Box>

      <Paper elevation={2}>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow sx={{ backgroundColor: 'grey.50' }}>
                <TableCell sx={{ fontWeight: 'bold' }}>Document Type</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>File Name</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Upload Date</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Status</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {documents.map((document) => (
                <TableRow key={document.id} hover>
                  <TableCell sx={{ fontWeight: 'medium' }}>{document.documentTypeName}</TableCell>
                  <TableCell>{document.fileName}</TableCell>
                  <TableCell>{new Date(document.uploadDate).toLocaleDateString()}</TableCell>
                  <TableCell>
                    <Chip
                      label={document.isMandatory ? 'Mandatory' : 'Optional'}
                      color={document.isMandatory ? 'error' : 'default'}
                      size="small"
                      variant="outlined"
                    />
                  </TableCell>
                  <TableCell>
                    <IconButton
                      size="small"
                      onClick={() => handleDownload(document)}
                      sx={{ mr: 1 }}
                      color="primary"
                    >
                      <DownloadIcon />
                    </IconButton>
                    <IconButton
                      size="small"
                      onClick={() => handleDelete(document.id)}
                      color="error"
                    >
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
              {documents.length === 0 && (
                <TableRow>
                  <TableCell colSpan={5} align="center" sx={{ py: 4 }}>
                    <Typography color="text.secondary">
                      No documents uploaded. Click "Upload Document" to add one.
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Upload Dialog */}
      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Upload Document</DialogTitle>
        <DialogContent>
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, pt: 1 }}>
            <FormControl fullWidth required>
              <InputLabel>Document Type</InputLabel>
              <Select
                value={formData.documentTypeId}
                label="Document Type"
                onChange={(e) => setFormData({ ...formData, documentTypeId: e.target.value as string })}
              >
                <MenuItem value="" disabled>
                  <em>Select Document Type</em>
                </MenuItem>
                {documentTypes.map((type) => (
                  <MenuItem key={type.id} value={String(type.id)}>
                    {type.name} {type.isMandatory && '(Mandatory)'}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>

            <Button
              variant="outlined"
              component="label"
              startIcon={<UploadIcon />}
              fullWidth
              sx={{ py: 2 }}
            >
              {selectedFile ? selectedFile.name : 'Select File (PDF, JPG, PNG)'}
              <input
                type="file"
                hidden
                accept=".pdf,.jpg,.jpeg,.png"
                onChange={handleFileSelect}
              />
            </Button>

            <TextField
              label="Description (Optional)"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              fullWidth
              multiline
              rows={2}
            />
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>Cancel</Button>
          <Button onClick={handleUpload} variant="contained" disabled={!selectedFile}>
            Upload
          </Button>
        </DialogActions>
      </Dialog>

      {/* Snackbar for notifications */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.severity} onClose={() => setSnackbar({ ...snackbar, open: false })}>
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default EmployeeDocuments;

