import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Alert,
  Snackbar,
  FormControl,
  FormLabel,
  RadioGroup,
  FormControlLabel,
  Radio,
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  AccountBalance as BankIcon,
} from '@mui/icons-material';
import { apiService } from '../../services/api';

interface Bank {
  id: number;
  name: string;
  ifscCode: string;
  branchName: string;
  address: string;
  city: string;
  state: string;
  isActive: boolean;
}

const BankList: React.FC = () => {
  const [banks, setBanks] = useState<Bank[]>([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [editingBank, setEditingBank] = useState<Bank | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    ifscCode: '',
    branchName: '',
    address: '',
    city: '',
    state: '',
    isActive: true,
  });
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

  useEffect(() => {
    loadBanks();
  }, []);

  const loadBanks = async () => {
    try {
      setLoading(true);
      const response = await apiService.getBanks();
      setBanks(response.data || []);
    } catch (error) {
      console.error('Error loading banks:', error);
      setSnackbar({ open: true, message: 'Failed to load banks', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    setEditingBank(null);
    setFormData({
      name: '',
      ifscCode: '',
      branchName: '',
      address: '',
      isActive: true,
    });
    setOpen(true);
  };

  const handleEdit = (bank: Bank) => {
    setEditingBank(bank);
    setFormData({
      name: bank.name,
      ifscCode: bank.ifscCode,
      branchName: bank.branchName,
      address: bank.address,
      city: bank.city || '',
      state: bank.state || '',
      isActive: bank.isActive,
    });
    setOpen(true);
  };

  const handleSave = async () => {
    try {
      if (editingBank) {
        await apiService.updateBank(editingBank.id!, formData);
        setSnackbar({ open: true, message: 'Bank updated successfully', severity: 'success' });
      } else {
        await apiService.createBank(formData);
        setSnackbar({ open: true, message: 'Bank created successfully', severity: 'success' });
      }
      setOpen(false);
      loadBanks();
    } catch (error) {
      console.error('Error saving bank:', error);
      setSnackbar({ open: true, message: 'Failed to save bank', severity: 'error' });
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('Are you sure you want to delete this bank?')) {
      try {
        await apiService.deleteBank(id);
        setSnackbar({ open: true, message: 'Bank deleted successfully', severity: 'success' });
        loadBanks();
      } catch (error) {
        console.error('Error deleting bank:', error);
        setSnackbar({ open: true, message: 'Failed to delete bank', severity: 'error' });
      }
    }
  };

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <BankIcon sx={{ fontSize: 32, color: 'primary.main' }} />
          <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold' }}>
            Banks Management
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleAdd}
          sx={{ borderRadius: 2 }}
        >
          Add Bank
        </Button>
      </Box>

      <Paper elevation={2}>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow sx={{ backgroundColor: 'grey.50' }}>
                <TableCell sx={{ fontWeight: 'bold' }}>Bank Name</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>IFSC Code</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Branch Name</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Address</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Status</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {banks.map((bank) => (
                <TableRow key={bank.id} hover>
                  <TableCell sx={{ fontWeight: 'medium' }}>{bank.name}</TableCell>
                  <TableCell>
                    <Typography variant="body2" sx={{ fontFamily: 'monospace', fontWeight: 'bold' }}>
                      {bank.ifscCode}
                    </Typography>
                  </TableCell>
                  <TableCell>{bank.branchName}</TableCell>
                  <TableCell>{bank.address}</TableCell>
                  <TableCell>
                    <Chip
                      label={bank.isActive ? 'Active' : 'Inactive'}
                      color={bank.isActive ? 'success' : 'default'}
                      size="small"
                    />
