      setAlert({
        type: 'error',
        message: 'Failed to fetch work locations',
      });
    }
  };

  const handleCreateHoliday = () => {
    setFormData({
      name: '',
      date: null,
      type: 'COMPANY',
      locationId: 0,
      isOptional: false,
      description: '',
    });
    setDialog({ open: true, mode: 'create', holiday: null });
  };

  const handleEditHoliday = (holiday: Holiday) => {
    setFormData({
      name: holiday.name,
      date: new Date(holiday.date),
      type: holiday.type,
      locationId: holiday.locationId || 0,
      isOptional: holiday.isOptional,
      description: holiday.description || '',
    });
    setDialog({ open: true, mode: 'edit', holiday });
  };

  const handleDeleteHoliday = async (holidayId: number) => {
    if (!window.confirm('Are you sure you want to delete this holiday?')) return;

    try {
      // TODO: Implement API call
      const response = await fetch(`/api/holidays/${holidayId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        setAlert({
          type: 'success',
          message: 'Holiday deleted successfully',
        });
        fetchHolidays();
      } else {
        const error = await response.json();
        setAlert({
          type: 'error',
          message: error.message || 'Failed to delete holiday',
        });
      }
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Network error. Please try again.',
      });
    }
  };

  const handleSubmit = async () => {
    if (!formData.name.trim() || !formData.date) {
      setAlert({
        type: 'error',
        message: 'Please fill all required fields',
      });
      return;
    }

    if (formData.type === 'REGIONAL' && !formData.locationId) {
      setAlert({
        type: 'error',
        message: 'Please select a location for regional holidays',
      });
      return;
    }

    setLoading(true);
    try {
      const url = dialog.mode === 'create' 
        ? '/api/holidays' 
        : `/api/holidays/${dialog.holiday?.id}`;

      const method = dialog.mode === 'create' ? 'POST' : 'PUT';

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`,
        },
        body: JSON.stringify({
          name: formData.name,
          date: formData.date?.toISOString().split('T')[0],
          type: formData.type,
          locationId: formData.type === 'REGIONAL' ? formData.locationId : null,
          isOptional: formData.isOptional,
          description: formData.description,
        }),
      });

      if (response.ok) {
        setAlert({
          type: 'success',
          message: `Holiday ${dialog.mode === 'create' ? 'created' : 'updated'} successfully`,
        });
        fetchHolidays();
        setDialog({ open: false, mode: 'create', holiday: null });
      } else {
        const error = await response.json();
        setAlert({
          type: 'error',
          message: error.message || `Failed to ${dialog.mode} holiday`,
        });
      }
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Network error. Please try again.',
      });
    } finally {
      setLoading(false);
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'NATIONAL': return <Public />;
      case 'REGIONAL': return <LocationOn />;
      case 'COMPANY': return <Business />;
      default: return <CalendarToday />;
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'NATIONAL': return 'primary';
      case 'REGIONAL': return 'secondary';
      case 'COMPANY': return 'info';
      default: return 'default';
    }
  };

  const getHolidayStats = () => {
    const total = holidays.length;
    const national = holidays.filter(h => h.type === 'NATIONAL').length;
    const regional = holidays.filter(h => h.type === 'REGIONAL').length;
    const company = holidays.filter(h => h.type === 'COMPANY').length;
    const optional = holidays.filter(h => h.isOptional).length;

    return { total, national, regional, company, optional };
  };

  const stats = getHolidayStats();

  return (
    <LocalizationProvider dateAdapter={AdapterDateFns}>
      <Container maxWidth="xl" sx={{ mt: 4, mb: 4 }}>
        <Paper elevation={3} sx={{ p: 4 }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
            <Typography variant="h4" component="h1">
              Holiday Calendar Management
            </Typography>
            <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
              <FormControl sx={{ minWidth: 120 }}>
                <InputLabel>Year</InputLabel>
                <Select
                  value={selectedYear}
                  onChange={(e) => setSelectedYear(e.target.value as number)}
                  size="small"
                >
                  {[2023, 2024, 2025, 2026].map(year => (
                    <MenuItem key={year} value={year}>{year}</MenuItem>
                  ))}
                </Select>
              </FormControl>
              <Button
                variant="outlined"
                startIcon={<Download />}
                onClick={() => {/* TODO: Export holidays */}}
              >
                Export
              </Button>
              <Button
                variant="outlined"
                startIcon={<Upload />}
                onClick={() => {/* TODO: Import holidays */}}
              >
                Import
              </Button>
            </Box>
          </Box>

          {alert && (
            <Alert 
              severity={alert.type} 
              sx={{ mb: 3 }}
              onClose={() => setAlert(null)}
            >
              {alert.message}
            </Alert>
          )}

          {/* Statistics Cards */}
          <Box sx={{ display: 'flex', gap: 3, mb: 3, flexWrap: 'wrap' }}>
            <Box sx={{ flex: '1 1 200px', minWidth: '180px' }}>
              <Card>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="h6" color="primary.main">
                    Total Holidays
                  </Typography>
                  <Typography variant="h3">{stats.total}</Typography>
                </CardContent>
              </Card>
            </Box>
            <Box sx={{ flex: '1 1 200px', minWidth: '180px' }}>
              <Card>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="h6" color="primary.main">
                    National
                  </Typography>
                  <Typography variant="h3">{stats.national}</Typography>
                </CardContent>
              </Card>
            </Box>
            <Box sx={{ flex: '1 1 200px', minWidth: '180px' }}>
              <Card>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="h6" color="secondary.main">
                    Regional
                  </Typography>
                  <Typography variant="h3">{stats.regional}</Typography>
                </CardContent>
              </Card>
            </Box>
            <Box sx={{ flex: '1 1 200px', minWidth: '180px' }}>
              <Card>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="h6" color="info.main">
                    Company
                  </Typography>
                  <Typography variant="h3">{stats.company}</Typography>
                </CardContent>
              </Card>
            </Box>
            <Box sx={{ flex: '1 1 200px', minWidth: '180px' }}>
              <Card>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="h6" color="warning.main">
                    Optional
                  </Typography>
                  <Typography variant="h3">{stats.optional}</Typography>
                </CardContent>
              </Card>
            </Box>
          </Box>

          {/* Holidays Table */}
          <TableContainer component={Paper} variant="outlined">
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Holiday Name</TableCell>
                  <TableCell>Date</TableCell>
                  <TableCell>Day</TableCell>
                  <TableCell>Type</TableCell>
                  <TableCell>Location</TableCell>
                  <TableCell>Optional</TableCell>
                  <TableCell>Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {holidays.map((holiday) => (
                  <TableRow key={holiday.id}>
                    <TableCell>
                      <Box>
                        <Typography variant="body2" fontWeight="bold">
                          {holiday.name}
                        </Typography>
                        {holiday.description && (
                          <Typography variant="caption" color="textSecondary">
                            {holiday.description}
                          </Typography>
                        )}
                      </Box>
                    </TableCell>
                    <TableCell>{new Date(holiday.date).toLocaleDateString()}</TableCell>
                    <TableCell>
                      {new Date(holiday.date).toLocaleDateString('en-US', { weekday: 'long' })}
                    </TableCell>
                    <TableCell>
                      <Chip
                        icon={getTypeIcon(holiday.type)}
                        label={holiday.type}
                        color={getTypeColor(holiday.type) as any}
                        size="small"
                      />
                    </TableCell>
                    <TableCell>
                      {holiday.locationName || 'All Locations'}
                    </TableCell>
                    <TableCell>
                      <Chip
                        label={holiday.isOptional ? 'Optional' : 'Mandatory'}
                        color={holiday.isOptional ? 'warning' : 'success'}
                        size="small"
                        variant="outlined"
                      />
                    </TableCell>
                    <TableCell>
                      <Box sx={{ display: 'flex', gap: 1 }}>
                        <IconButton
                          size="small"
                          onClick={() => handleEditHoliday(holiday)}
                        >
                          <Edit />
                        </IconButton>
                        <IconButton
                          size="small"
                          color="error"
                          onClick={() => handleDeleteHoliday(holiday.id)}
                        >
                          <Delete />
                        </IconButton>
                      </Box>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>

          {holidays.length === 0 && (
            <Box sx={{ textAlign: 'center', py: 4 }}>
              <Typography variant="h6" color="textSecondary">
                No holidays found for {selectedYear}
              </Typography>
              <Button
                variant="contained"
                onClick={handleCreateHoliday}
                sx={{ mt: 2 }}
                startIcon={<Add />}
              >
                Add First Holiday
              </Button>
            </Box>
          )}
        </Paper>

        {/* Floating Action Button */}
        <Fab
          color="primary"
          aria-label="add holiday"
          sx={{ position: 'fixed', bottom: 16, right: 16 }}
          onClick={handleCreateHoliday}
        >
          <Add />
        </Fab>

        {/* Create/Edit Holiday Dialog */}
        <Dialog 
          open={dialog.open} 
          onClose={() => setDialog({ open: false, mode: 'create', holiday: null })}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>
            {dialog.mode === 'create' ? 'Add New Holiday' : 'Edit Holiday'}
          </DialogTitle>
          <DialogContent>
            <TextField
              fullWidth
              label="Holiday Name"
              value={formData.name}
              onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
              sx={{ mb: 3, mt: 2 }}
              required
            />

            <DatePicker
              label="Holiday Date"
              value={formData.date}
              onChange={(newValue) => setFormData(prev => ({ ...prev, date: newValue }))}
              sx={{ mb: 3, width: '100%' }}
            />

            <FormControl fullWidth sx={{ mb: 3 }}>
              <InputLabel>Holiday Type</InputLabel>
              <Select
                value={formData.type}
                onChange={(e) => setFormData(prev => ({ ...prev, type: e.target.value as any }))}
              >
                <MenuItem value="NATIONAL">National</MenuItem>
                <MenuItem value="REGIONAL">Regional</MenuItem>
                <MenuItem value="COMPANY">Company</MenuItem>
              </Select>
            </FormControl>

            {formData.type === 'REGIONAL' && (
              <FormControl fullWidth sx={{ mb: 3 }}>
                <InputLabel>Location</InputLabel>
                <Select
                  value={formData.locationId}
                  onChange={(e) => setFormData(prev => ({ ...prev, locationId: e.target.value as number }))}
                >
                  {workLocations.map((location) => (
                    <MenuItem key={location.id} value={location.id}>
                      {location.name} ({location.city})
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            )}

            <FormControl fullWidth sx={{ mb: 3 }}>
              <InputLabel>Holiday Nature</InputLabel>
              <Select
                value={formData.isOptional.toString()}
                onChange={(e) => setFormData(prev => ({ ...prev, isOptional: e.target.value === 'true' }))}
              >
                <MenuItem value="false">Mandatory</MenuItem>
                <MenuItem value="true">Optional</MenuItem>
              </Select>
            </FormControl>

            <TextField
              fullWidth
              label="Description"
              multiline
              rows={3}
              value={formData.description}
              onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
              placeholder="Add description for this holiday..."
            />
          </DialogContent>
          <DialogActions>
            <Button 
              onClick={() => setDialog({ open: false, mode: 'create', holiday: null })}
              disabled={loading}
            >
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              variant="contained"
              disabled={loading || !formData.name.trim() || !formData.date}
            >
              {loading ? 'Saving...' : dialog.mode === 'create' ? 'Add Holiday' : 'Update Holiday'}
            </Button>
          </DialogActions>
        </Dialog>
      </Container>
    </LocalizationProvider>
  );
};

export default HolidayCalendarForm;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Alert,
  Snackbar,
  FormControl,
  FormLabel,
  RadioGroup,
  FormControlLabel,
  Radio,
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Payment as PaymentIcon,
} from '@mui/icons-material';
import { apiService } from '../../services/api';

interface PaymentMode {
  id: number;
  name: string;
  description: string;
  isActive: boolean;
}

const PaymentModeList: React.FC = () => {
  const [paymentModes, setPaymentModes] = useState<PaymentMode[]>([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [editingMode, setEditingMode] = useState<PaymentMode | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    isActive: true,
  });
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

  useEffect(() => {
    loadPaymentModes();
  }, []);

  const loadPaymentModes = async () => {
    try {
      setLoading(true);
      const response = await apiService.getPaymentModes();
      setPaymentModes(response.data || []);
    } catch (error) {
      console.error('Error loading payment modes:', error);
      setSnackbar({ open: true, message: 'Failed to load payment modes', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    setEditingMode(null);
    setFormData({
      name: '',
      description: '',
      isActive: true,
    });
    setOpen(true);
  };

  const handleEdit = (mode: PaymentMode) => {
    setEditingMode(mode);
    setFormData({
      name: mode.name,
      description: mode.description,
      isActive: mode.isActive,
    });
    setOpen(true);
  };

  const handleSave = async () => {
    try {
      if (editingMode) {
        await apiService.updatePaymentMode(editingMode.id!, formData);
        setSnackbar({ open: true, message: 'Payment mode updated successfully', severity: 'success' });
      } else {
        await apiService.createPaymentMode(formData);
        setSnackbar({ open: true, message: 'Payment mode created successfully', severity: 'success' });
      }
      setOpen(false);
      loadPaymentModes();
    } catch (error) {
      console.error('Error saving payment mode:', error);
      setSnackbar({ open: true, message: 'Failed to save payment mode', severity: 'error' });
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('Are you sure you want to delete this payment mode?')) {
      try {
        await apiService.deletePaymentMode(id);
        setSnackbar({ open: true, message: 'Payment mode deleted successfully', severity: 'success' });
        loadPaymentModes();
      } catch (error) {
        console.error('Error deleting payment mode:', error);
        setSnackbar({ open: true, message: 'Failed to delete payment mode', severity: 'error' });
      }
    }
  };

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <PaymentIcon sx={{ fontSize: 32, color: 'primary.main' }} />
          <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold' }}>
            Payment Modes
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleAdd}
          sx={{ borderRadius: 2 }}
        >
          Add Payment Mode
        </Button>
      </Box>

      <Paper elevation={2}>
        <TableContainer>
          <Table>
            <TableHead>
              <TableRow sx={{ backgroundColor: 'grey.50' }}>
                <TableCell sx={{ fontWeight: 'bold' }}>Name</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Description</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Status</TableCell>
                <TableCell sx={{ fontWeight: 'bold' }}>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {paymentModes.map((mode) => (
                <TableRow key={mode.id} hover>
                  <TableCell sx={{ fontWeight: 'medium' }}>{mode.name}</TableCell>
                  <TableCell>{mode.description}</TableCell>
                  <TableCell>
                    <Chip
                      label={mode.isActive ? 'Active' : 'Inactive'}
                      color={mode.isActive ? 'success' : 'default'}
                      size="small"
                    />
                  </TableCell>
                  <TableCell>
                    <IconButton
                      size="small"
                      onClick={() => handleEdit(mode)}
                      sx={{ mr: 1 }}
                    >
                      <EditIcon />
                    </IconButton>
                    <IconButton
                      size="small"
                      onClick={() => handleDelete(mode.id)}
                      color="error"
                    >
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
              {paymentModes.length === 0 && (
                <TableRow>
                  <TableCell colSpan={4} align="center" sx={{ py: 4 }}>
                    <Typography color="text.secondary">
                      No payment modes found. Click "Add Payment Mode" to create one.
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      </Paper>

      {/* Add/Edit Dialog */}
      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>
          {editingMode ? 'Edit Payment Mode' : 'Add New Payment Mode'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, pt: 1 }}>
            <TextField
              label="Payment Mode Name"
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              fullWidth
              required
              placeholder="e.g., Bank Transfer, UPI, Cash"
            />
            <TextField
              label="Description"
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              fullWidth
              multiline
              rows={3}
              placeholder="Describe the payment method and its characteristics (e.g., Direct bank transfer to employee account, processed monthly on salary date)"
              helperText="Explain how this payment mode works, processing time, and any special requirements"
            />

            <FormControl component="fieldset">
              <FormLabel component="legend" sx={{ mb: 1, fontWeight: 'bold' }}>Status</FormLabel>
              <RadioGroup
                row
                value={formData.isActive ? 'active' : 'inactive'}
                onChange={(e) => setFormData({ ...formData, isActive: e.target.value === 'active' })}
              >
                <FormControlLabel
                  value="active"
                  control={<Radio />}
                  label={
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <Typography>Active</Typography>
                      <Chip label="Visible" size="small" color="success" />
                    </Box>
                  }
                />
                <FormControlLabel
                  value="inactive"
                  control={<Radio />}
                  label={
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      <Typography>Inactive</Typography>
                      <Chip label="Hidden" size="small" color="default" />
                    </Box>
                  }
                />
              </RadioGroup>
            </FormControl>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>Cancel</Button>
          <Button onClick={handleSave} variant="contained">
            {editingMode ? 'Update' : 'Create'}
          </Button>
        </DialogActions>
      </Dialog>

      {/* Snackbar for notifications */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.severity} onClose={() => setSnackbar({ ...snackbar, open: false })}>
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default PaymentModeList;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
    Box,
    Paper,
    Typography,
    Button,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    IconButton,
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    TextField,
    Chip,
    Alert,
    Snackbar,
    FormControl,
    FormLabel,
    RadioGroup,
    FormControlLabel,
    Radio,
} from '@mui/material';
import {
    Add as AddIcon,
    Edit as EditIcon,
    Delete as DeleteIcon,
    Work as ProjectIcon,
} from '@mui/icons-material';
import { apiService, Project } from '../../services/api';

const ProjectList: React.FC = () => {
    const [projects, setProjects] = useState<Project[]>([]);
    const [loading, setLoading] = useState(false);
    const [open, setOpen] = useState(false);
    const [editingProject, setEditingProject] = useState<Project | null>(null);
    const [formData, setFormData] = useState({
        name: '',
        code: '',
        description: '',
        isActive: true,
    });
    const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

    useEffect(() => {
        loadProjects();
    }, []);

    const loadProjects = async () => {
        try {
            setLoading(true);
            const response = await apiService.getProjects();
            setProjects(response.data || []);
        } catch (error) {
            console.error('Error loading projects:', error);
            setSnackbar({ open: true, message: 'Failed to load projects', severity: 'error' });
        } finally {
            setLoading(false);
        }
    };

    const handleAdd = () => {
        setEditingProject(null);
        setFormData({
            name: '',
            code: '',
            description: '',
            isActive: true,
        });
        setOpen(true);
    };

    const handleEdit = (project: Project) => {
        setEditingProject(project);
        setFormData({
            name: project.name,
            code: project.code || '',
            description: project.description || '',
            isActive: project.isActive ?? true,
        });
        setOpen(true);
    };

    const validateForm = () => {
        const errors: string[] = [];

        if (!formData.name.trim()) errors.push('Project name is required');
        if (formData.name.length < 2) errors.push('Project name must be at least 2 characters');

        return errors;
    };

    const handleSave = async () => {
        const validationErrors = validateForm();
        if (validationErrors.length > 0) {
            setSnackbar({
                open: true,
                message: 'Please fix the following errors:\n' + validationErrors.join('\n'),
                severity: 'error'
            });
            return;
        }

        try {
            if (editingProject) {
                await apiService.updateProject(editingProject.id!, formData);
                setSnackbar({ open: true, message: 'Project updated successfully', severity: 'success' });
            } else {
                await apiService.createProject(formData);
                setSnackbar({ open: true, message: 'Project created successfully', severity: 'success' });
            }
            setOpen(false);
            loadProjects();
        } catch (error: any) {
            console.error('Error saving project:', error);
