    status: 'DRAFT',
    postedDate: new Date().toISOString().split('T')[0],
    postedBy: 1, // Current user ID
    isActive: true,
  });

  useEffect(() => {
    loadMasterData();
    if (isEdit && id) {
      loadJobPosting(parseInt(id));
    }
  }, [isEdit, id]);

  const loadMasterData = async () => {
    try {
      const [departmentsRes, designationsRes, workLocationsRes, qualificationsRes] = await Promise.all([
        apiService.getDepartments(),
        apiService.getDesignations(),
        apiService.getWorkLocations(),
        apiService.getQualifications()
      ]);

      setDepartments(departmentsRes.data || []);
      setDesignations(designationsRes.data || []);
      setWorkLocations(workLocationsRes.data || []);
      setQualifications(qualificationsRes.data || []);
    } catch (error) {
      console.error('Error loading master data:', error);
      // Fallback data
      setDepartments([
        { id: 1, name: 'Human Resources' },
        { id: 2, name: 'Information Technology' },
        { id: 3, name: 'Finance' },
      ]);
      setDesignations([
        { id: 1, name: 'HR Manager', departmentId: 1 },
        { id: 3, name: 'Software Engineer', departmentId: 2 },
        { id: 6, name: 'Accountant', departmentId: 3 },
      ]);
      setWorkLocations([
        { id: 1, name: 'Mumbai Office' },
        { id: 2, name: 'Delhi Office' },
        { id: 3, name: 'Bangalore Office' },
      ]);
      setQualifications([
        { id: 1, name: 'Bachelor\'s Degree' },
        { id: 2, name: 'Master\'s Degree' },
      ]);
    }
  };

  const loadJobPosting = async (jobId: number) => {
    try {
      setLoading(true);
      // In real app: const response = await apiService.getJobPostingById(jobId);
    } catch (error) {
      console.error('Error loading job posting:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field: keyof JobPosting) => (
    event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement> | any
  ) => {
    const value = event.target.value;
    setJobPosting(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleDepartmentChange = (event: any) => {
    const departmentId = event.target.value;
    setJobPosting(prev => ({
      ...prev,
      departmentId: departmentId,
      designationId: 0 // Reset designation when department changes
    }));
  };

  const handleSkillsChange = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      const skill = (event.target as HTMLInputElement).value.trim();
      if (skill && !jobPosting.skills.includes(skill)) {
        setJobPosting(prev => ({
          ...prev,
          skills: [...prev.skills, skill]
        }));
        (event.target as HTMLInputElement).value = '';
      }
    }
  };

  const removeSkill = (skillToRemove: string) => {
    setJobPosting(prev => ({
      ...prev,
      skills: prev.skills.filter(skill => skill !== skillToRemove)
    }));
  };

  const handleQualificationChange = (event: any) => {
    const value = event.target.value as number[];
    setJobPosting(prev => ({
      ...prev,
      qualificationIds: value
    }));
  };

  const validateForm = () => {
    const errors: string[] = [];

    if (!jobPosting.title.trim()) errors.push('Job Title is required');
    if (!jobPosting.departmentId) errors.push('Department is required');
    if (!jobPosting.designationId) errors.push('Designation is required');
    if (!jobPosting.workLocationId) errors.push('Work Location is required');
    if (!jobPosting.description.trim()) errors.push('Job Description is required');
    if (!jobPosting.requirements.trim()) errors.push('Requirements are required');
    if (!jobPosting.responsibilities.trim()) errors.push('Responsibilities are required');
    if (!jobPosting.applicationDeadline) errors.push('Application Deadline is required');
    if (jobPosting.minSalary >= jobPosting.maxSalary && jobPosting.maxSalary > 0) {
      errors.push('Maximum Salary must be greater than Minimum Salary');
    }
    if (jobPosting.minExperience > jobPosting.maxExperience) {
      errors.push('Maximum Experience must be greater than or equal to Minimum Experience');
    }

    return errors;
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();

    const validationErrors = validateForm();
    if (validationErrors.length > 0) {
      setSnackbar({
        open: true,
        message: 'Please fix the following errors:\n' + validationErrors.join('\n'),
        severity: 'error'
      });
      return;
    }

    try {
      setLoading(true);
      if (isEdit && id) {
        // await apiService.updateJobPosting(parseInt(id), jobPosting);
        setSnackbar({ open: true, message: 'Job posting updated successfully!', severity: 'success' });
      } else {
        // await apiService.createJobPosting(jobPosting);
        setSnackbar({ open: true, message: 'Job posting created successfully!', severity: 'success' });
      }
      setTimeout(() => navigate('/recruitment/jobs'), 1500);
    } catch (error) {
      console.error('Error saving job posting:', error);
      setSnackbar({ open: true, message: 'Error saving job posting. Please try again.', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate('/recruitment/jobs');
  };

  const getFilteredDesignations = () => {
    return designations.filter(d => d.departmentId === jobPosting.departmentId);
  };

  return (
    <Box>
      <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold', mb: 1 }}>
        {isEdit ? 'Edit Job Posting' : 'Create Job Posting'}
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Create and manage job postings for recruitment.
      </Typography>
      <Paper elevation={2} sx={{ p: 3 }}>
        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            {/* Basic Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom>
                Basic Information
              </Typography>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Job Title"
                required
                value={jobPosting.title}
                onChange={handleInputChange('title')}
                placeholder="e.g., Senior Software Engineer"
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <FormControl fullWidth required>
                <InputLabel>Job Type</InputLabel>
                <Select
                  value={jobPosting.jobType}
                  label="Job Type"
                  onChange={handleInputChange('jobType')}
                >
                  <MenuItem value="FULL_TIME">Full Time</MenuItem>
                  <MenuItem value="PART_TIME">Part Time</MenuItem>
                  <MenuItem value="CONTRACT">Contract</MenuItem>
                  <MenuItem value="INTERNSHIP">Internship</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth required>
                <InputLabel>Department</InputLabel>
                <Select
                  value={jobPosting.departmentId || ''}
                  label="Department"
                  onChange={handleDepartmentChange}
                >
                  {departments.map((dept) => (
                    <MenuItem key={dept.id} value={dept.id}>
                      {dept.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth required>
                <InputLabel>Designation</InputLabel>
                <Select
                  value={jobPosting.designationId || ''}
                  label="Designation"
                  onChange={handleInputChange('designationId')}
                  disabled={!jobPosting.departmentId}
                >
                  {getFilteredDesignations().map((designation) => (
                    <MenuItem key={designation.id} value={designation.id}>
                      {designation.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth required>
                <InputLabel>Work Location</InputLabel>
                <Select
                  value={jobPosting.workLocationId || ''}
                  label="Work Location"
                  onChange={handleInputChange('workLocationId')}
                >
                  {workLocations.map((location) => (
                    <MenuItem key={location.id} value={location.id}>
                      {location.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            {/* Experience & Salary */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Experience & Compensation
              </Typography>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <FormControl fullWidth>
                <InputLabel>Experience Level</InputLabel>
                <Select
                  value={jobPosting.experienceLevel}
                  label="Experience Level"
                  onChange={handleInputChange('experienceLevel')}
                >
                  <MenuItem value="ENTRY">Entry Level</MenuItem>
                  <MenuItem value="MID">Mid Level</MenuItem>
                  <MenuItem value="SENIOR">Senior Level</MenuItem>
                  <MenuItem value="EXECUTIVE">Executive</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <TextField
                fullWidth
                label="Min Experience (Years)"
                type="number"
                value={jobPosting.minExperience}
                onChange={handleInputChange('minExperience')}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <TextField
                fullWidth
                label="Max Experience (Years)"
                type="number"
                value={jobPosting.maxExperience}
                onChange={handleInputChange('maxExperience')}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <FormControl fullWidth>
                <InputLabel>Status</InputLabel>
                <Select
                  value={jobPosting.status}
                  label="Status"
                  onChange={handleInputChange('status')}
                >
                  <MenuItem value="DRAFT">Draft</MenuItem>
                  <MenuItem value="ACTIVE">Active</MenuItem>
                  <MenuItem value="CLOSED">Closed</MenuItem>
                  <MenuItem value="ON_HOLD">On Hold</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Min Salary"
                type="number"
                value={jobPosting.minSalary}
                onChange={handleInputChange('minSalary')}
                InputProps={{ startAdornment: '₹' }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Max Salary"
                type="number"
                value={jobPosting.maxSalary}
                onChange={handleInputChange('maxSalary')}
                InputProps={{ startAdornment: '₹' }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Application Deadline"
                type="date"
                required
                value={jobPosting.applicationDeadline}
                onChange={handleInputChange('applicationDeadline')}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>

            {/* Job Details */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Job Details
              </Typography>
            </Grid>

            <Grid size={12}>
              <TextField
                fullWidth
                label="Job Description"
                multiline
                rows={4}
                required
                value={jobPosting.description}
                onChange={handleInputChange('description')}
                placeholder="Provide a detailed description of the job role..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Requirements"
                multiline
                rows={4}
                required
                value={jobPosting.requirements}
                onChange={handleInputChange('requirements')}
                placeholder="List the required qualifications and skills..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Responsibilities"
                multiline
                rows={4}
                required
                value={jobPosting.responsibilities}
                onChange={handleInputChange('responsibilities')}
                placeholder="Describe the key responsibilities..."
              />
            </Grid>

            <Grid size={12}>
              <TextField
                fullWidth
                label="Benefits"
                multiline
                rows={3}
                value={jobPosting.benefits}
                onChange={handleInputChange('benefits')}
                placeholder="List the benefits and perks offered..."
              />
            </Grid>

            {/* Skills */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Skills & Qualifications
              </Typography>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Required Skills"
                placeholder="Type a skill and press Enter"
                onKeyPress={handleSkillsChange}
                helperText="Press Enter to add skills"
              />
              <Box sx={{ mt: 1, display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                {jobPosting.skills.map((skill, index) => (
                  <Chip
                    key={index}
                    label={skill}
                    onDelete={() => removeSkill(skill)}
                    size="small"
                  />
                ))}
              </Box>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <FormControl fullWidth>
                <InputLabel>Required Qualifications</InputLabel>
                <Select
                  multiple
                  value={jobPosting.qualificationIds}
                  onChange={handleQualificationChange}
                  renderValue={(selected) => (
                    <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
                      {(selected as number[]).map((value) => {
                        const qualification = qualifications.find(q => q.id === value);
                        return (
                          <Chip key={value} label={qualification?.name} size="small" />
                        );
                      })}
                    </Box>
                  )}
                >
                  {qualifications.map((qualification) => (
                    <MenuItem key={qualification.id} value={qualification.id}>
                      {qualification.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid size={12}>
              <Box sx={{ display: 'flex', justifyContent: 'flex-end', gap: 2, mt: 3 }}>
                <Button
                  variant="outlined"
                  startIcon={<CancelIcon />}
                  onClick={handleCancel}
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  variant="contained"
                  startIcon={<SaveIcon />}
                  disabled={loading}
                >
                  {loading ? 'Saving...' : isEdit ? 'Update Job Posting' : 'Create Job Posting'}
                </Button>
              </Box>
            </Grid>
          </Grid>
        </form>
      </Paper>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
      >
        <Alert
          severity={snackbar.severity}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
          variant="filled"
          sx={{ whiteSpace: 'pre-line' }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default JobPostingForm;

import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  Button,
  Card,
  CardContent,
  IconButton,
  CircularProgress,
  Alert,
  Snackbar,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
} from '@mui/material';
import {
  ArrowBack as ArrowBackIcon,
  Analytics as AnalyticsIcon,
  Download as DownloadIcon,
  Print as PrintIcon,
  PieChart as PieChartIcon,
  BarChart as BarChartIcon,
  TrendingUp as TrendingUpIcon,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { apiService, Employee, Department, Designation, ManpowerType } from '../../services/api';

interface AnalyticsData {
  departmentDistribution: { name: string; count: number; percentage: number }[];
  designationDistribution: { name: string; count: number; percentage: number }[];
  manpowerTypeDistribution: { name: string; count: number; percentage: number }[];
  monthlyJoining: { month: string; count: number }[];
  totalEmployees: number;
  activeEmployees: number;
  averageAge: number;
  genderDistribution: { male: number; female: number; other: number };
}

const EmployeeAnalytics: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [analyticsData, setAnalyticsData] = useState<AnalyticsData | null>(null);
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' as 'success' | 'error' });
  const [selectedChart, setSelectedChart] = useState('department');

  useEffect(() => {
    loadAnalyticsData();
  }, []);

  const loadAnalyticsData = async () => {
    try {
      setLoading(true);

      // Load employee data and calculate analytics
      const employeesRes = await apiService.getEmployees();
      const departmentsRes = await apiService.getDepartments();
      const designationsRes = await apiService.getDesignations();
      const manpowerTypesRes = await apiService.getManpowerTypes();

      const employees = Array.isArray(employeesRes.data) ? employeesRes.data : (employeesRes.data?.content || []);
      const departments = departmentsRes.data || [];
      const designations = designationsRes.data || [];
      const manpowerTypes = manpowerTypesRes.data || [];

      // Calculate department distribution
      const departmentCounts = departments.map((dept: Department) => {
        const count = employees.filter((emp: Employee) => emp.department?.id === dept.id).length;
        return {
          name: dept.name,
          count,
          percentage: employees.length > 0 ? (count / employees.length) * 100 : 0
        };
      });

      // Calculate designation distribution
      const designationCounts = designations.map((desig: Designation) => {
        const count = employees.filter((emp: Employee) => emp.designation?.id === desig.id).length;
        return {
          name: desig.name,
          count,
          percentage: employees.length > 0 ? (count / employees.length) * 100 : 0
        };
      });

      // Calculate manpower type distribution
      const manpowerTypeCounts = manpowerTypes.map((type: ManpowerType) => {
        const count = employees.filter((emp: Employee) => emp.manpowerType?.id === type.id).length;
        return {
          name: type.name,
          count,
          percentage: employees.length > 0 ? (count / employees.length) * 100 : 0
        };
      });

      // Calculate monthly joining trends (last 12 months)
      const monthlyJoining = [];
      const currentDate = new Date();
      for (let i = 11; i >= 0; i--) {
        const date = new Date(currentDate.getFullYear(), currentDate.getMonth() - i, 1);
        const monthName = date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
        const count = employees.filter((emp: Employee) => {
          if (!emp.joiningDate) return false;
          const joinDate = new Date(emp.joiningDate);
          return joinDate.getMonth() === date.getMonth() && joinDate.getFullYear() === date.getFullYear();
        }).length;
        monthlyJoining.push({ month: monthName, count });
      }

      // Calculate gender distribution
      const genderDistribution = {
        male: employees.filter((emp: Employee) => emp.gender?.toLowerCase() === 'male').length,
        female: employees.filter((emp: Employee) => emp.gender?.toLowerCase() === 'female').length,
        other: employees.filter((emp: Employee) => emp.gender && !['male', 'female'].includes(emp.gender.toLowerCase())).length
      };

      // Calculate average age
      const currentYear = new Date().getFullYear();
      const employeesWithAge = employees.filter((emp: Employee) => emp.dateOfBirth);
      const averageAge = employeesWithAge.length > 0 
        ? employeesWithAge.reduce((sum: number, emp: Employee) => {
            const birthYear = new Date(emp.dateOfBirth).getFullYear();
            return sum + (currentYear - birthYear);
          }, 0) / employeesWithAge.length
        : 0;

      setAnalyticsData({
        departmentDistribution: departmentCounts,
        designationDistribution: designationCounts,
        manpowerTypeDistribution: manpowerTypeCounts,
        monthlyJoining,
        totalEmployees: employees.length,
        activeEmployees: employees.filter((emp: Employee) => emp.isActive !== false).length,
        averageAge: Math.round(averageAge),
        genderDistribution
      });

    } catch (error) {
      console.error('Error loading analytics data:', error);
      setSnackbar({ open: true, message: 'Failed to load analytics data', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleExport = (format: 'pdf' | 'excel') => {
    setSnackbar({ 
      open: true, 
      message: `${format.toUpperCase()} export started. Download will begin shortly.`, 
      severity: 'success' 
    });
  };

  const renderSimpleChart = (data: { name: string; count: number; percentage: number }[], title: string) => {
    const maxCount = Math.max(...data.map(item => item.count));

    return (
      <Card sx={{ height: '100%' }}>
        <CardContent>
          <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
            <BarChartIcon /> {title}
          </Typography>
          <Box sx={{ maxHeight: 300, overflow: 'auto' }}>
            {data.map((item, index) => (
              <Box key={index} sx={{ mb: 2 }}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
                  <Typography variant="body2" sx={{ fontWeight: 'medium' }}>
                    {item.name}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {item.count} ({item.percentage.toFixed(1)}%)
                  </Typography>
                </Box>
                <Box sx={{ 
                  width: '100%', 
                  height: 8, 
                  bgcolor: 'grey.200', 
                  borderRadius: 1,
                  overflow: 'hidden'
                }}>
                  <Box sx={{ 
                    width: `${maxCount > 0 ? (item.count / maxCount) * 100 : 0}%`, 
                    height: '100%', 
                    bgcolor: `hsl(${(index * 360) / data.length}, 70%, 50%)`,
                    transition: 'width 0.3s ease'
                  }} />
                </Box>
              </Box>
            ))}
          </Box>
        </CardContent>
      </Card>
    );
  };

  const renderTrendChart = (data: { month: string; count: number }[]) => {
    const maxCount = Math.max(...data.map(item => item.count));

    return (
      <Card sx={{ height: '100%' }}>
        <CardContent>
          <Typography variant="h6" sx={{ fontWeight: 'bold', mb: 2, display: 'flex', alignItems: 'center', gap: 1 }}>
            <TrendingUpIcon /> Monthly Joining Trends
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'end', gap: 1, height: 200, overflow: 'auto' }}>
            {data.map((item, index) => (
              <Box key={index} sx={{ 
                display: 'flex', 
                flexDirection: 'column', 
                alignItems: 'center',
                minWidth: 60
              }}>
                <Typography variant="caption" sx={{ mb: 1, fontWeight: 'bold' }}>
                  {item.count}
                </Typography>
                <Box sx={{ 
                  width: 40, 
                  height: `${maxCount > 0 ? (item.count / maxCount) * 150 : 0}px`,
                  bgcolor: 'primary.main',
                  borderRadius: '4px 4px 0 0',
                  minHeight: 4,
                  transition: 'height 0.3s ease'
                }} />
                <Typography variant="caption" sx={{ mt: 1, transform: 'rotate(-45deg)', fontSize: '0.7rem' }}>
                  {item.month}
                </Typography>
              </Box>
            ))}
          </Box>
        </CardContent>
      </Card>
    );
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: 400 }}>
        <CircularProgress />
      </Box>
    );
  }

  if (!analyticsData) {
    return (
      <Box sx={{ textAlign: 'center', py: 4 }}>
        <Typography variant="h6" color="text.secondary">
          No analytics data available
        </Typography>
      </Box>
    );
  }

  return (
    <Box>
      {/* Header */}
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
          <IconButton onClick={() => navigate('/reports')} sx={{ mr: 1 }}>
            <ArrowBackIcon />
          </IconButton>
          <AnalyticsIcon sx={{ fontSize: 32, color: 'primary.main' }} />
          <Typography variant="h4" sx={{ fontWeight: 'bold' }}>
            Employee Analytics Dashboard
          </Typography>
        </Box>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <Button
            variant="outlined"
            startIcon={<PrintIcon />}
            onClick={() => window.print()}
          >
            Print
          </Button>
          <Button
