interface EmployeeDocument {
  id: number;
  documentTypeId: number;
  documentTypeName: string;
  documentNumber: string;
  fileName: string;
  filePath: string;
  fileExtension: string;
  fileSizeBytes: number;
  isVerified: boolean;
  verificationNotes?: string;
  verifiedAt?: string;
  verifiedBy?: string;
