}

interface UploadState {
  file: File | null;
  documentTypeId: number;
  documentNumber: string;
  uploading: boolean;
  progress: number;
}

const DocumentUploadForm: React.FC = () => {
  const [documentTypes, setDocumentTypes] = useState<DocumentType[]>([]);
  const [employeeDocuments, setEmployeeDocuments] = useState<EmployeeDocument[]>([]);
  const [loading, setLoading] = useState(false);
  const [alert, setAlert] = useState<{
    type: 'success' | 'error' | 'warning' | 'info';
    message: string;
  } | null>(null);

  const [uploadDialog, setUploadDialog] = useState(false);
  const [uploadState, setUploadState] = useState<UploadState>({
    file: null,
    documentTypeId: 0,
    documentNumber: '',
    uploading: false,
    progress: 0,
  });

  const sampleEmployeeDocuments: EmployeeDocument[] = [
    {
      id: 1,
      documentTypeId: 1,
      documentTypeName: 'Aadhar Card',
      documentNumber: '1234-5678-9012',
      fileName: 'aadhar_john_doe.pdf',
      filePath: '/uploads/documents/aadhar_john_doe.pdf',
      fileExtension: 'pdf',
      fileSizeBytes: 1024000,
      isVerified: true,
      verifiedAt: '2024-03-01',
      verifiedBy: 'HR Manager',
      uploadedAt: '2024-02-15',
    },
    {
      id: 2,
      documentTypeId: 2,
      documentTypeName: 'PAN Card',
      documentNumber: 'ABCDE1234F',
      fileName: 'pan_john_doe.pdf',
      filePath: '/uploads/documents/pan_john_doe.pdf',
      fileExtension: 'pdf',
      fileSizeBytes: 512000,
      isVerified: false,
      uploadedAt: '2024-02-20',
    },
  ];

  useEffect(() => {
    fetchDocumentTypes();
    fetchEmployeeDocuments();
  }, []);

  const fetchDocumentTypes = async () => {
    try {
      const response = await apiService.getDocumentTypes();
      setDocumentTypes(response.data || []);
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Failed to fetch document types',
      });
    }
  };

  const fetchEmployeeDocuments = async () => {
    setLoading(true);
    try {
      // TODO: Implement API call
      setEmployeeDocuments(sampleEmployeeDocuments);
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Failed to fetch employee documents',
      });
    } finally {
      setLoading(false);
    }
  };

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setUploadState(prev => ({ ...prev, file }));
    }
  };

  const validateFile = (file: File, documentType: DocumentType): string | null => {
    const fileExtension = file.name.split('.').pop()?.toLowerCase();
    const allowedExtensions = documentType.allowedExtensions?.split(',') || [];

    if (!fileExtension || !allowedExtensions.includes(fileExtension)) {
      return `Invalid file type. Allowed: ${documentType.allowedExtensions}`;
    }

    if (file.size > (documentType.maxFileSizeMb || 0) * 1024 * 1024) {
      return `File size too large. Maximum: ${documentType.maxFileSizeMb}MB`;
    }

    return null;
  };

  const handleUpload = async () => {
    if (!uploadState.file || !uploadState.documentTypeId || !uploadState.documentNumber.trim()) {
      setAlert({
        type: 'error',
        message: 'Please fill all required fields and select a file',
      });
      return;
    }

    const documentType = documentTypes.find(dt => dt.id === uploadState.documentTypeId);
    if (!documentType) return;

    const validationError = validateFile(uploadState.file, documentType);
    if (validationError) {
      setAlert({
        type: 'error',
        message: validationError,
      });
      return;
    }

    setUploadState(prev => ({ ...prev, uploading: true, progress: 0 }));

    try {
      const formData = new FormData();
      formData.append('document', uploadState.file);
      formData.append('documentTypeId', uploadState.documentTypeId.toString());
      formData.append('documentNumber', uploadState.documentNumber);

      // Simulate upload progress
      const interval = setInterval(() => {
        setUploadState(prev => ({
          ...prev,
          progress: Math.min(prev.progress + 10, 90)
        }));
      }, 200);

      // TODO: Implement actual API call
      const response = await fetch('/api/employee/documents/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`,
        },
        body: formData,
      });

      clearInterval(interval);
      setUploadState(prev => ({ ...prev, progress: 100 }));

      if (response.ok) {
        setAlert({
          type: 'success',
          message: 'Document uploaded successfully',
        });
        fetchEmployeeDocuments(); // Refresh documents list
        setUploadDialog(false);
        resetUploadState();
      } else {
        const error = await response.json();
        setAlert({
          type: 'error',
          message: error.message || 'Failed to upload document',
        });
      }
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Network error. Please try again.',
      });
    } finally {
      setUploadState(prev => ({ ...prev, uploading: false, progress: 0 }));
    }
  };

  const resetUploadState = () => {
    setUploadState({
      file: null,
      documentTypeId: 0,
      documentNumber: '',
      uploading: false,
      progress: 0,
    });
  };

  const handleDeleteDocument = async (documentId: number) => {
    if (!window.confirm('Are you sure you want to delete this document?')) return;

    try {
      // TODO: Implement API call
      const response = await fetch(`/api/employee/documents/${documentId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`,
        },
      });

      if (response.ok) {
        setAlert({
          type: 'success',
          message: 'Document deleted successfully',
        });
        fetchEmployeeDocuments();
      } else {
        const error = await response.json();
        setAlert({
          type: 'error',
          message: error.message || 'Failed to delete document',
        });
      }
    } catch (error) {
      setAlert({
        type: 'error',
        message: 'Network error. Please try again.',
      });
    }
  };

  const formatFileSize = (bytes: number): string => {
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    if (bytes === 0) return '0 Byte';
    const i = parseInt(Math.floor(Math.log(bytes) / Math.log(1024)).toString());
    return Math.round(bytes / Math.pow(1024, i) * 100) / 100 + ' ' + sizes[i];
  };

  const getDocumentStatus = (document: EmployeeDocument) => {
    if (document.isVerified) {
      return { label: 'Verified', color: 'success', icon: <CheckCircle /> };
    } else {
      return { label: 'Pending Verification', color: 'warning', icon: <Schedule /> };
    }
  };

  const getCompletionStats = () => {
    const mandatoryDocs = documentTypes.filter(dt => dt.isMandatory);
    const uploadedMandatory = mandatoryDocs.filter(dt => 
      employeeDocuments.some(ed => ed.documentTypeId === dt.id)
    );

    return {
      mandatory: uploadedMandatory.length,
      total: mandatoryDocs.length,
      percentage: mandatoryDocs.length > 0 ? (uploadedMandatory.length / mandatoryDocs.length) * 100 : 0,
    };
  };

  const completionStats = getCompletionStats();

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Paper elevation={3} sx={{ p: 4 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
          <Typography variant="h4" component="h1">
            Document Upload Center
          </Typography>
          <Button
            variant="contained"
            startIcon={<CloudUpload />}
            onClick={() => setUploadDialog(true)}
          >
            Upload Document
          </Button>
        </Box>

        {alert && (
          <Alert 
            severity={alert.type} 
            sx={{ mb: 3 }}
            onClose={() => setAlert(null)}
          >
            {alert.message}
          </Alert>
        )}

        {/* Completion Progress */}
        <Card sx={{ mb: 3 }}>
          <CardContent>
            <Typography variant="h6" gutterBottom>
              Document Completion Progress
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
              <Box sx={{ width: '100%', mr: 1 }}>
                <LinearProgress variant="determinate" value={completionStats.percentage} />
              </Box>
              <Box sx={{ minWidth: 35 }}>
                <Typography variant="body2" color="textSecondary">
                  {Math.round(completionStats.percentage)}%
                </Typography>
              </Box>
            </Box>
            <Typography variant="body2" color="textSecondary">
              {completionStats.mandatory} of {completionStats.total} mandatory documents uploaded
            </Typography>
          </CardContent>
        </Card>

        {/* Document Categories */}
        <Box sx={{ display: 'flex', gap: 3, flexWrap: 'wrap' }}>
          <Box sx={{ flex: '1 1 400px', minWidth: '300px' }}>
            <Typography variant="h6" gutterBottom>
              Mandatory Documents
            </Typography>
            <List>
              {documentTypes.filter(dt => dt.isMandatory).map((docType) => {
                const uploadedDoc = employeeDocuments.find(ed => ed.documentTypeId === docType.id);
                const status = uploadedDoc ? getDocumentStatus(uploadedDoc) : null;

                return (
                  <ListItem key={docType.id}>
                    <ListItemIcon>
                      {uploadedDoc ? (
                        status?.icon
                      ) : (
                        <Error color="error" />
                      )}
                    </ListItemIcon>
                    <ListItemText
                      primary={docType.name}
                      secondary={
                        uploadedDoc ? (
                          <Box>
                            <Typography variant="caption" display="block">
                              {uploadedDoc.fileName} • {formatFileSize(uploadedDoc.fileSizeBytes)}
                            </Typography>
                            <Chip
                              label={status?.label}
                              color={status?.color as any}
                              size="small"
                              sx={{ mt: 0.5 }}
                            />
                          </Box>
                        ) : (
                          <Typography variant="caption" color="error">
                            Not uploaded
                          </Typography>
                        )
                      }
                    />
                    <ListItemSecondaryAction>
                      {uploadedDoc ? (
                        <Box sx={{ display: 'flex', gap: 1 }}>
                          <IconButton
                            size="small"
                            onClick={() => {/* TODO: View document */}}
                          >
                            <Visibility />
                          </IconButton>
                          <IconButton
                            size="small"
                            onClick={() => {/* TODO: Download document */}}
                          >
                            <Download />
                          </IconButton>
                          <IconButton
                            size="small"
                            color="error"
                            onClick={() => handleDeleteDocument(uploadedDoc.id)}
                          >
                            <Delete />
                          </IconButton>
                        </Box>
                      ) : (
                        <Button
                          size="small"
                          variant="outlined"
                          onClick={() => {
                            setUploadState(prev => ({ ...prev, documentTypeId: docType.id || 0 }));
                            setUploadDialog(true);
                          }}
                        >
                          Upload
                        </Button>
                      )}
                    </ListItemSecondaryAction>
                  </ListItem>
                );
              })}
            </List>
          </Box>

          <Box sx={{ flex: '1 1 400px', minWidth: '300px' }}>
            <Typography variant="h6" gutterBottom>
              Optional Documents
            </Typography>
            <List>
              {documentTypes.filter(dt => !dt.isMandatory).map((docType) => {
                const uploadedDoc = employeeDocuments.find(ed => ed.documentTypeId === docType.id);
                const status = uploadedDoc ? getDocumentStatus(uploadedDoc) : null;

                return (
                  <ListItem key={docType.id}>
                    <ListItemIcon>
                      {uploadedDoc ? (
                        status?.icon
                      ) : (
                        <Description color="disabled" />
                      )}
                    </ListItemIcon>
                    <ListItemText
                      primary={docType.name}
                      secondary={
                        uploadedDoc ? (
                          <Box>
                            <Typography variant="caption" display="block">
                              {uploadedDoc.fileName} • {formatFileSize(uploadedDoc.fileSizeBytes)}
                            </Typography>
                            <Chip
                              label={status?.label}
                              color={status?.color as any}
                              size="small"
                              sx={{ mt: 0.5 }}
                            />
                          </Box>
                        ) : (
                          <Typography variant="caption" color="textSecondary">
                            Optional
                          </Typography>
                        )
                      }
                    />
                    <ListItemSecondaryAction>
                      {uploadedDoc ? (
                        <Box sx={{ display: 'flex', gap: 1 }}>
                          <IconButton
                            size="small"
                            onClick={() => {/* TODO: View document */}}
                          >
                            <Visibility />
                          </IconButton>
                          <IconButton
                            size="small"
                            onClick={() => {/* TODO: Download document */}}
                          >
                            <Download />
                          </IconButton>
                          <IconButton
                            size="small"
                            color="error"
                            onClick={() => handleDeleteDocument(uploadedDoc.id)}
                          >
                            <Delete />
                          </IconButton>
                        </Box>
                      ) : (
                        <Button
                          size="small"
                          variant="outlined"
                          onClick={() => {
                            setUploadState(prev => ({ ...prev, documentTypeId: docType.id || 0 }));
                            setUploadDialog(true);
                          }}
                        >
                          Upload
                        </Button>
                      )}
                    </ListItemSecondaryAction>
                  </ListItem>
                );
              })}
            </List>
          </Box>
        </Box>
      </Paper>

      {/* Upload Dialog */}
      <Dialog 
        open={uploadDialog} 
        onClose={() => !uploadState.uploading && setUploadDialog(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>Upload Document</DialogTitle>
        <DialogContent>
          <FormControl fullWidth sx={{ mb: 3, mt: 2 }}>
            <InputLabel>Document Type</InputLabel>
            <Select
              value={uploadState.documentTypeId}
              onChange={(e) => setUploadState(prev => ({ ...prev, documentTypeId: e.target.value as number }))}
              disabled={uploadState.uploading}
            >
              {documentTypes.map((docType) => (
                <MenuItem key={docType.id} value={docType.id}>
                  {docType.name} {docType.isMandatory && '(Mandatory)'}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <TextField
            fullWidth
            label="Document Number"
            value={uploadState.documentNumber}
            onChange={(e) => setUploadState(prev => ({ ...prev, documentNumber: e.target.value }))}
            disabled={uploadState.uploading}
            sx={{ mb: 3 }}
            helperText="Enter the document number (e.g., Aadhar number, PAN number)"
          />

          <Box sx={{ mb: 3 }}>
            <Button
              variant="outlined"
              component="label"
              fullWidth
              startIcon={<CloudUpload />}
              disabled={uploadState.uploading}
              sx={{ height: 100, border: '2px dashed', borderColor: 'primary.main' }}
            >
              {uploadState.file ? (
                <Box sx={{ textAlign: 'center' }}>
                  <Typography variant="body2">{uploadState.file.name}</Typography>
                  <Typography variant="caption" color="textSecondary">
                    {formatFileSize(uploadState.file.size)}
                  </Typography>
                </Box>
              ) : (
                <Box sx={{ textAlign: 'center' }}>
                  <Typography variant="body2">Click to select file</Typography>
                  <Typography variant="caption" color="textSecondary">
                    or drag and drop
                  </Typography>
                </Box>
              )}
              <input
                type="file"
                hidden
                onChange={handleFileSelect}
                accept=".pdf,.jpg,.jpeg,.png,.doc,.docx"
              />
            </Button>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={() => {
              setUploadDialog(false);
              resetUploadState();
            }}
            disabled={uploadState.uploading}
          >
            Cancel
          </Button>
          <Button
            onClick={handleUpload}
            variant="contained"
            disabled={
              uploadState.uploading || 
              !uploadState.file || 
              !uploadState.documentTypeId || 
              !uploadState.documentNumber.trim()
            }
          >
            {uploadState.uploading ? 'Uploading...' : 'Upload Document'}
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default DocumentUploadForm;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Avatar,
  IconButton,
  Alert,
  Snackbar,
  Divider,
} from '@mui/material';
import {
  Save as SaveIcon,
  Cancel as CancelIcon,
  PhotoCamera as PhotoCameraIcon,
  Edit as EditIcon,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { apiService } from '../../services/api';

interface EmployeeProfile {
  id: number;
  employeeId: string;
  firstName: string;
  middleName?: string;
  lastName: string;
  email: string;
  mobile: string;
  dateOfBirth: string;
  gender: 'MALE' | 'FEMALE' | 'OTHER';
  address: string;
  city: string;
  state: string;
  pincode: string;
  photoPath?: string;
  emergencyContactName: string;
  emergencyContactNumber: string;
  emergencyContactRelation: string;
  personalEmail?: string;
  alternateNumber?: string;
  maritalStatus: 'SINGLE' | 'MARRIED' | 'DIVORCED' | 'WIDOWED';
  bloodGroup?: string;
  manpowerTypeId?: number;
  departmentId?: number;
  designationId?: number;
  workLocationId?: number;
  shiftId?: number;
  joiningDate?: string;
}

const ProfileUpdateForm: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'success' as 'success' | 'error' | 'warning'
  });

  const [profile, setProfile] = useState<EmployeeProfile>({
    id: 1,
    employeeId: 'EMP001',
    firstName: '',
    lastName: '',
    email: '',
    mobile: '',
    dateOfBirth: '',
    gender: 'MALE',
    address: '',
    city: '',
    state: '',
    pincode: '',
    emergencyContactName: '',
    emergencyContactNumber: '',
    emergencyContactRelation: '',
    maritalStatus: 'SINGLE',
    manpowerTypeId: 0,
    departmentId: 0,
    designationId: 0,
    workLocationId: 0,
    shiftId: 0,
    joiningDate: '',
  });

  const [rawPhotoPath, setRawPhotoPath] = useState<string | undefined>(undefined);
  const [originalProfile, setOriginalProfile] = useState<EmployeeProfile>(profile);

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    try {
      setLoading(true);
      const response = await apiService.getCurrentEmployeeProfile();
      if (response.success && response.data) {
        const data = response.data;
        const mappedProfile: EmployeeProfile = {
          id: data.id,
          employeeId: data.employeeId,
          firstName: data.firstName || '',
          lastName: data.lastName || '',
          email: data.email || '',
          mobile: data.mobile || '',
          dateOfBirth: data.dateOfBirth || '',
          gender: data.gender || 'MALE',
          address: data.address || '',
          city: data.city || '',
          state: data.state || '',
          pincode: data.pincode || '',
          photoPath: data.photoPath ? `http://localhost:8080${data.photoPath}` : undefined,
          emergencyContactName: data.emergencyContactName || '',
          emergencyContactNumber: data.emergencyContactNumber || '',
          emergencyContactRelation: data.emergencyContactRelation || '',
          personalEmail: data.personalEmail || '',
          alternateNumber: data.alternateNumber || '',
          maritalStatus: data.maritalStatus || 'SINGLE',
          bloodGroup: data.bloodGroup || '',
          manpowerTypeId: data.manpowerTypeId,
          departmentId: data.departmentId,
          designationId: data.designationId,
          workLocationId: data.workLocationId,
          shiftId: data.shiftId,
          joiningDate: data.joiningDate,
        };
        setRawPhotoPath(data.photoPath);
        setProfile(mappedProfile);
        setOriginalProfile(mappedProfile);
      } else {
        setSnackbar({ open: true, message: response.message || 'Error loading profile', severity: 'error' });
      }
    } catch (error) {
      console.error('Error loading profile:', error);
      setSnackbar({ open: true, message: 'Error loading profile', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const [selectedPhoto, setSelectedPhoto] = useState<File | null>(null);

  const handlePhotoChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setSelectedPhoto(file);
      const reader = new FileReader();
      reader.onload = (e) => {
        setProfile(prev => ({ ...prev, photoPath: e.target?.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleInputChange = (field: keyof EmployeeProfile) => (
    event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement> | any
  ) => {
    const value = event.target.value;
    setProfile(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const validateForm = () => {
    const errors: string[] = [];

    if (!profile.firstName?.trim()) errors.push('First Name is required');
    if (!profile.lastName?.trim()) errors.push('Last Name is required');
    if (!profile.mobile?.trim()) errors.push('Mobile number is required');
    if (!profile.address?.trim()) errors.push('Address is required');
    if (!profile.city?.trim()) errors.push('City is required');
    if (!profile.state?.trim()) errors.push('State is required');
    if (!profile.pincode?.trim()) errors.push('Pincode is required');
    if (!profile.emergencyContactName?.trim()) errors.push('Emergency Contact Name is required');
    if (!profile.emergencyContactNumber?.trim()) errors.push('Emergency Contact Number is required');

    // Mobile validation
    const mobileRegex = /^[0-9]{10,15}$/;
    if (profile.mobile && !mobileRegex.test(profile.mobile)) {
      errors.push('Please enter a valid mobile number');
    }

    if (profile.emergencyContactNumber && !mobileRegex.test(profile.emergencyContactNumber)) {
      errors.push('Please enter a valid emergency contact number');
    }

    return errors;
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();

    const validationErrors = validateForm();
    if (validationErrors.length > 0) {
      setSnackbar({
        open: true,
        message: 'Please fix the following errors:\n' + validationErrors.join('\n'),
        severity: 'error'
      });
      return;
    }

    try {
      setLoading(true);
      const updateData: any = { ...profile };

      // Handle photoPath: if new photo selected, it's handled by updateEmployeeWithPhoto.
      // If not, we should send the raw relative path, not the full URL preview.
      if (selectedPhoto) {
        delete updateData.photoPath;
      } else {
        updateData.photoPath = rawPhotoPath;
      }

      console.log('Submitting profile update:', updateData);

      let response;
      if (selectedPhoto) {
        response = await apiService.updateEmployeeWithPhoto(profile.id, updateData, selectedPhoto);
      } else {
        response = await apiService.updateEmployee(profile.id, updateData);
      }

      if (response.success) {
        setSnackbar({ open: true, message: 'Profile updated successfully!', severity: 'success' });
        loadProfile(); // Reload to get updated data and paths
        setEditMode(false);
        setSelectedPhoto(null);
      } else {
        console.error('Update failed:', response);
        setSnackbar({ open: true, message: response.message || 'Error updating profile', severity: 'error' });
      }
    } catch (error) {
      console.error('Error updating profile:', error);
      setSnackbar({ open: true, message: 'Error updating profile. Please try again.', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setProfile(originalProfile);
    setEditMode(false);
  };

  const handleEdit = () => {
    setEditMode(true);
  };

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold' }}>
          My Profile
        </Typography>
        {!editMode && (
          <Button
            variant="contained"
            startIcon={<EditIcon />}
            onClick={handleEdit}
          >
            Edit Profile
          </Button>
        )}
      </Box>
      <Paper elevation={2} sx={{ p: 3 }}>
        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            {/* Profile Photo Section */}
            <Grid sx={{ textAlign: 'center', mb: 2 }} size={12}>
              <Avatar
                sx={{ width: 120, height: 120, mx: 'auto', mb: 2 }}
                src={profile.photoPath}
              >
                {profile.firstName?.charAt(0)}{profile.lastName?.charAt(0)}
              </Avatar>
              {editMode && (
                <>
                  <IconButton color="primary" component="label">
                    <input hidden accept="image/*" type="file" onChange={handlePhotoChange} />
                    <PhotoCameraIcon />
                  </IconButton>
                  <Typography variant="caption" display="block">
                    Update Photo
                  </Typography>
                </>
              )}
            </Grid>

            {/* Basic Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom>
                Basic Information
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Employee ID"
                value={profile.employeeId}
                InputProps={{ readOnly: true }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="First Name"
                required
                value={profile.firstName}
                onChange={handleInputChange('firstName')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Last Name"
                required
                value={profile.lastName}
                onChange={handleInputChange('lastName')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Official Email"
                value={profile.email}
                InputProps={{ readOnly: true }}
                variant={editMode ? "outlined" : "standard"}
                helperText="Contact HR to change official email"
              />
            </Grid>



            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Mobile Number"
                required
                value={profile.mobile}
                onChange={handleInputChange('mobile')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Alternate Number"
                value={profile.alternateNumber || ''}
                onChange={handleInputChange('alternateNumber')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Date of Birth"
                type="date"
                value={profile.dateOfBirth}
                InputProps={{ readOnly: true }}
                InputLabelProps={{ shrink: true }}
                variant={editMode ? "outlined" : "standard"}
                helperText="Contact HR to change date of birth"
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth variant={editMode ? "outlined" : "standard"}>
                <InputLabel id="profile-gender-label" shrink={!!profile.gender || true}>Gender</InputLabel>
                <Select
                  labelId="profile-gender-label"
                  value={profile.gender}
                  label="Gender"
                  onChange={handleInputChange('gender')}
                  disabled={!editMode}
                  displayEmpty
                  renderValue={(selected: any) => {
                    if (!selected || selected === '' || selected === null || selected === undefined) {
                      return <span style={{
                        color: 'rgba(0, 0, 0, 0.6)',
                        fontSize: '0.875rem',
                        display: 'inline-block',
                        overflow: 'visible',
                        textOverflow: 'clip',
                        whiteSpace: 'nowrap',
                        width: '100%'
                      }}>Select Gender</span>;
                    }
                    return <span style={{
                      color: 'rgba(0, 0, 0, 0.87)',
                      fontSize: '0.875rem',
                      display: 'inline-block',
                      overflow: 'visible',
                      textOverflow: 'clip',
                      whiteSpace: 'nowrap'
                    }}>{selected === 'MALE' ? 'Male' : selected === 'FEMALE' ? 'Female' : 'Other'}</span>;
                  }}
                  sx={{
                    '& .MuiSelect-select': {
                      paddingLeft: '20px !important',
                      paddingRight: '40px !important',
                      paddingTop: '14px !important',
                      paddingBottom: '14px !important',
                      overflow: 'visible !important',
                      textOverflow: 'clip !important',
                      whiteSpace: 'nowrap !important',
                      width: '100% !important',
                      boxSizing: 'border-box !important',
                      '@media (max-width:600px)': {
                        paddingLeft: '16px !important',
                        paddingRight: '32px !important',
                        paddingTop: '10px !important',
                        paddingBottom: '10px !important',
                      },
                    },
                    '& .MuiSelect-select > span': {
                      overflow: 'visible !important',
                      textOverflow: 'clip !important',
                      whiteSpace: 'nowrap !important',
                      maxWidth: 'none !important',
                      width: 'auto !important',
                    },
                  }}
                >
                  <MenuItem value="MALE">Male</MenuItem>
                  <MenuItem value="FEMALE">Female</MenuItem>
                  <MenuItem value="OTHER">Other</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth variant={editMode ? "outlined" : "standard"}>
                <InputLabel>Marital Status</InputLabel>
                <Select
                  value={profile.maritalStatus}
                  label="Marital Status"
                  onChange={handleInputChange('maritalStatus')}
                  disabled={!editMode}
                >
                  <MenuItem value="SINGLE">Single</MenuItem>
                  <MenuItem value="MARRIED">Married</MenuItem>
                  <MenuItem value="DIVORCED">Divorced</MenuItem>
                  <MenuItem value="WIDOWED">Widowed</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Blood Group"
                value={profile.bloodGroup || ''}
                onChange={handleInputChange('bloodGroup')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            {/* Address Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Address Information
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid size={12}>
              <TextField
                fullWidth
                label="Address"
                multiline
                rows={2}
                required
                value={profile.address}
                onChange={handleInputChange('address')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="City"
                required
                value={profile.city}
                onChange={handleInputChange('city')}
                InputProps={{ readOnly: !editMode }}
                variant={editMode ? "outlined" : "standard"}
