            title="In Progress"
            value={stats.inProgress}
            type="inProgress"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <DashboardStatCard
            title="Completed"
            value={stats.completed}
            type="completed"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={3}>
          <DashboardStatCard
            title="Total Tasks"
            value={stats.total}
            type="total"
          />
