      // In real app: await apiService.enrollEmployeesInTraining(enrollmentData);

      // Update local state
      setEmployees(prev => 
        prev.map(emp => 
          enrollmentData.employeeIds.includes(emp.id)
            ? { 
                ...emp, 
                isEnrolled: true, 
                enrollmentDate: enrollmentData.enrollmentDate,
                completionStatus: 'NOT_STARTED' as const
              }
            : emp
        )
      );

      setPrograms(prev =>
        prev.map(prog =>
          prog.id === enrollmentData.programId
            ? { ...prog, enrolledCount: prog.enrolledCount + enrollmentData.employeeIds.length }
            : prog
        )
      );

      setSnackbar({
        open: true,
        message: `Successfully enrolled ${enrollmentData.employeeIds.length} employees in training!`,
        severity: 'success'
      });

      setEnrollmentDialog(false);
      setSelectedEmployees([]);
    } catch (error) {
      console.error('Error enrolling employees:', error);
      setSnackbar({ open: true, message: 'Error enrolling employees. Please try again.', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'COMPLETED': return 'success';
      case 'IN_PROGRESS': return 'info';
      case 'FAILED': return 'error';
      case 'NOT_STARTED': return 'default';
      default: return 'default';
    }
  };

  const getCompletionPercentage = (status: string) => {
    switch (status) {
      case 'COMPLETED': return 100;
      case 'IN_PROGRESS': return 50;
      case 'FAILED': return 25;
      case 'NOT_STARTED': return 0;
      default: return 0;
    }
  };

  const selectedProgramData = programs.find(p => p.id === selectedProgram);
  const availableSpots = selectedProgramData ? selectedProgramData.maxParticipants - selectedProgramData.enrolledCount : 0;

  return (
    <Box>
      <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold', mb: 1 }}>
        Training Enrollment
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Enroll employees in training programs and track their progress.
      </Typography>
      {/* Program Selection */}
      <Paper elevation={2} sx={{ p: 3, mb: 3 }}>
        <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <TrainingIcon />
          Select Training Program
        </Typography>

        <Grid container spacing={3}>
          <Grid
            size={{
              xs: 12,
              md: 6
            }}>
            <FormControl fullWidth>
              <InputLabel>Training Program</InputLabel>
              <Select
                value={selectedProgram}
                label="Training Program"
                onChange={(e) => handleProgramChange(e.target.value as number)}
              >
                <MenuItem value={0}>Select a program...</MenuItem>
                {programs.map((program) => (
                  <MenuItem key={program.id} value={program.id}>
                    {program.title} - {program.category}
                  </MenuItem>
                ))}
              </Select>
            </FormControl>
          </Grid>

          {selectedProgramData && (
            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <Card variant="outlined">
                <CardContent sx={{ py: 2 }}>
                  <Typography variant="body2" gutterBottom>
                    <strong>Duration:</strong> {selectedProgramData.duration} hours
                  </Typography>
                  <Typography variant="body2" gutterBottom>
                    <strong>Dates:</strong> {new Date(selectedProgramData.startDate).toLocaleDateString()} - {new Date(selectedProgramData.endDate).toLocaleDateString()}
                  </Typography>
                  <Typography variant="body2" gutterBottom>
                    <strong>Capacity:</strong> {selectedProgramData.enrolledCount}/{selectedProgramData.maxParticipants} enrolled
                  </Typography>
                  <Typography variant="body2">
                    <strong>Available Spots:</strong> {availableSpots}
                  </Typography>
                  <LinearProgress 
                    variant="determinate" 
                    value={(selectedProgramData.enrolledCount / selectedProgramData.maxParticipants) * 100}
                    sx={{ mt: 1 }}
                  />
                </CardContent>
              </Card>
            </Grid>
          )}
        </Grid>
      </Paper>
      {/* Employee Selection */}
      {selectedProgram > 0 && (
        <Paper elevation={2} sx={{ p: 3 }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <GroupIcon />
              Select Employees ({selectedEmployees.length} selected)
            </Typography>
            <Button
              variant="contained"
              startIcon={<EnrollIcon />}
              onClick={openEnrollmentDialog}
              disabled={selectedEmployees.length === 0}
            >
              Enroll Selected
            </Button>
          </Box>

          <TableContainer>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell padding="checkbox">
                    <Checkbox
                      indeterminate={selectedEmployees.length > 0 && selectedEmployees.length < employees.filter(e => !e.isEnrolled).length}
                      checked={employees.filter(e => !e.isEnrolled).length > 0 && selectedEmployees.length === employees.filter(e => !e.isEnrolled).length}
                      onChange={(e) => handleSelectAll(e.target.checked)}
                    />
                  </TableCell>
                  <TableCell>Employee</TableCell>
                  <TableCell>Department</TableCell>
                  <TableCell>Enrollment Status</TableCell>
                  <TableCell>Progress</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {employees.map((employee) => (
                  <TableRow key={employee.id}>
                    <TableCell padding="checkbox">
                      <Checkbox
                        checked={selectedEmployees.includes(employee.id)}
                        onChange={(e) => handleEmployeeSelection(employee.id, e.target.checked)}
                        disabled={employee.isEnrolled}
                      />
                    </TableCell>
                    <TableCell>
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                        <Avatar sx={{ width: 32, height: 32 }}>
                          {employee.name.charAt(0)}
                        </Avatar>
                        <Box>
                          <Typography variant="body2" fontWeight="bold">
                            {employee.name}
                          </Typography>
                          <Typography variant="caption" color="text.secondary">
                            {employee.employeeId} • {employee.email}
                          </Typography>
                        </Box>
                      </Box>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">{employee.department}</Typography>
                      <Typography variant="caption" color="text.secondary">
                        {employee.designation}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      {employee.isEnrolled ? (
                        <Box>
                          <Chip label="Enrolled" color="success" size="small" />
                          <Typography variant="caption" display="block" color="text.secondary">
                            {employee.enrollmentDate && new Date(employee.enrollmentDate).toLocaleDateString()}
                          </Typography>
                        </Box>
                      ) : (
                        <Chip label="Not Enrolled" color="default" size="small" />
                      )}
                    </TableCell>
                    <TableCell>
                      {employee.isEnrolled && employee.completionStatus ? (
                        <Box sx={{ width: '100%' }}>
                          <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                            <Typography variant="caption">
                              {employee.completionStatus.replace('_', ' ')}
                            </Typography>
                            <Typography variant="caption">
                              {getCompletionPercentage(employee.completionStatus)}%
                            </Typography>
                          </Box>
                          <LinearProgress
                            variant="determinate"
                            value={getCompletionPercentage(employee.completionStatus)}
                            color={getStatusColor(employee.completionStatus) as any}
                          />
                        </Box>
                      ) : (
                        <Typography variant="caption" color="text.secondary">
                          Not enrolled
                        </Typography>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </Paper>
      )}
      {/* Enrollment Confirmation Dialog */}
      <Dialog open={enrollmentDialog} onClose={() => setEnrollmentDialog(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Confirm Training Enrollment</DialogTitle>
        <DialogContent>
          <Typography variant="body1" gutterBottom>
            You are about to enroll <strong>{enrollmentData.employeeIds.length} employees</strong> in:
          </Typography>
          <Typography variant="h6" color="primary" gutterBottom>
            {selectedProgramData?.title}
          </Typography>

          <TextField
            fullWidth
            label="Enrollment Date"
            type="date"
            value={enrollmentData.enrollmentDate}
            onChange={(e) => setEnrollmentData(prev => ({ ...prev, enrollmentDate: e.target.value }))}
            InputLabelProps={{ shrink: true }}
            sx={{ mt: 2, mb: 2 }}
          />

          <TextField
            fullWidth
            label="Remarks (Optional)"
            multiline
            rows={3}
            value={enrollmentData.remarks || ''}
            onChange={(e) => setEnrollmentData(prev => ({ ...prev, remarks: e.target.value }))}
            placeholder="Add any remarks about this enrollment..."
          />

          <Alert severity="info" sx={{ mt: 2 }}>
            Enrolled employees will receive email notifications about the training schedule and requirements.
          </Alert>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setEnrollmentDialog(false)}>Cancel</Button>
          <Button 
            variant="contained" 
            onClick={submitEnrollment}
            disabled={loading}
          >
            {loading ? 'Enrolling...' : 'Confirm Enrollment'}
          </Button>
        </DialogActions>
      </Dialog>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
      >
        <Alert
          severity={snackbar.severity}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
          variant="filled"
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default TrainingEnrollmentForm;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
    Box, Paper, Typography, TextField, Button, Grid, Tab, Tabs,
    FormControl, InputLabel, Select, MenuItem, Table, TableBody,
    TableCell, TableContainer, TableHead, TableRow, IconButton,
    Chip, Dialog, DialogTitle, DialogContent, DialogActions,
    Alert, Snackbar, Card, CardContent, Avatar, Tooltip, Divider,
    Switch, FormControlLabel, LinearProgress,
} from '@mui/material';
import {
    School as TrainingIcon, Group as EnrollIcon, Add as AddIcon,
    Edit as EditIcon, Delete as DeleteIcon, Close as CloseIcon,
    PlayCircle as OngoingIcon, CheckCircle as CompletedIcon,
    Schedule as ScheduleIcon, Person as PersonIcon, Star as StarsIcon,
    Assignment as AssignmentIcon, CalendarMonth as CalIcon,
} from '@mui/icons-material';
import { apiService } from '../../services/api';

interface TabPanelProps { children?: React.ReactNode; index: number; value: number; }
const TabPanel = ({ children, value, index }: TabPanelProps) => (
    <div hidden={value !== index}>{value === index && <Box sx={{ pt: 3 }}>{children}</Box>}</div>
);

const trainingStatusColors: Record<string, 'default' | 'primary' | 'secondary' | 'error' | 'info' | 'success' | 'warning'> = {
    DRAFT: 'default', SCHEDULED: 'primary', ONGOING: 'warning', COMPLETED: 'success', CANCELLED: 'error'
};
const enrollmentStatusColors: Record<string, 'default' | 'primary' | 'secondary' | 'error' | 'info' | 'success' | 'warning'> = {
    ENROLLED: 'info', IN_PROGRESS: 'warning', COMPLETED: 'success'
};

const trainingCategories = ['Technical Skills', 'Soft Skills', 'Leadership', 'Compliance', 'Safety', 'Product Knowledge', 'Process Training', 'Orientation', 'Professional Development', 'Other'];

const TrainingManagementForm: React.FC = () => {
    const [tab, setTab] = useState(0);
    const [programs, setPrograms] = useState<any[]>([]);
    const [enrollments, setEnrollments] = useState<any[]>([]);
    const [employees, setEmployees] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [openDialog, setOpenDialog] = useState(false);
    const [editingItem, setEditingItem] = useState<any>(null);
    const [deleteDialog, setDeleteDialog] = useState<{ open: boolean; id: number; type: string }>({ open: false, id: 0, type: '' });
    const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' as any });

    const defaultProgram = { title: '', description: '', category: '', start_date: '', end_date: '', status: 'SCHEDULED' };
    const defaultEnrollment = { employee_id: '', training_program_id: '', status: 'ENROLLED' };

    const [programForm, setProgramForm] = useState({ ...defaultProgram });
    const [enrollForm, setEnrollForm] = useState({ ...defaultEnrollment });

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [progRes, enrollRes, empRes] = await Promise.all([
                apiService.getTrainingPrograms(),
                apiService.getEmployeeTraining(),
                apiService.getEmployees(1, 1000),
            ]);

            if (progRes.success) setPrograms(progRes.data || []);
            if (enrollRes.success) setEnrollments(enrollRes.data || []);

            const empData = empRes?.data?.content || empRes?.data || [];
            setEmployees(empData);
        } catch (err) {
            console.error(err);
            setSnackbar({ open: true, message: 'Failed to load data', severity: 'error' });
        } finally { setLoading(false); }
    };

    const handleSaveProgram = async () => {
        if (!programForm.title || !programForm.start_date) { setSnackbar({ open: true, message: 'Title and Start Date are required', severity: 'error' }); return; }
        try {
            const res = editingItem
                ? await apiService.updateTrainingProgram(editingItem.id, programForm)
                : await apiService.createTrainingProgram(programForm);

            if (res.success) {
                setSnackbar({ open: true, message: editingItem ? 'Program updated!' : 'Program created!', severity: 'success' });
                setOpenDialog(false);
                resetForms();
                loadData();
            } else {
                setSnackbar({ open: true, message: res.message || 'Error saving program', severity: 'error' });
            }
        } catch (err) {
            setSnackbar({ open: true, message: 'Server error', severity: 'error' });
        }
    };

    const handleSaveEnrollment = async () => {
        if (!enrollForm.employee_id || !enrollForm.training_program_id) {
            setSnackbar({ open: true, message: 'Please select employee and program', severity: 'error' });
            return;
        }
        try {
            const res = editingItem
                ? await apiService.updateEmployeeEnrollment(editingItem.id, enrollForm)
                : await apiService.enrollEmployee(enrollForm);
            if (res.success) {
                setSnackbar({ open: true, message: editingItem ? 'Enrollment updated!' : 'Employee enrolled!', severity: 'success' });
                setOpenDialog(false);
                resetForms();
                loadData();
            } else {
                setSnackbar({ open: true, message: res.message || 'Error enrolling employee', severity: 'error' });
            }
        } catch (err) {
            setSnackbar({ open: true, message: 'Server error', severity: 'error' });
        }
    };

    const handleDelete = async () => {
        try {
            const res = deleteDialog.type === 'program'
                ? await apiService.deleteTrainingProgram(deleteDialog.id)
                : await apiService.deleteEmployeeEnrollment(deleteDialog.id); // Implemented delete enrollment

            if (res.success) {
                setSnackbar({ open: true, message: 'Deleted successfully', severity: 'success' });
                setDeleteDialog({ open: false, id: 0, type: '' });
                loadData();
            } else {
                setSnackbar({ open: true, message: res.message || 'Error deleting', severity: 'error' });
            }
        } catch (err) {
            setSnackbar({ open: true, message: 'Error deleting', severity: 'error' });
        }
    };

    const resetForms = () => {
        setEditingItem(null);
        setProgramForm({ ...defaultProgram });
        setEnrollForm({ ...defaultEnrollment });
    };

    const summaryCards = [
        { label: 'Total Programs', value: programs.length, color: '#2563eb', bg: '#dbeafe', icon: <AssignmentIcon /> },
        { label: 'Active/Ongoing', value: programs.filter(p => p.status === 'ONGOING' || p.status === 'SCHEDULED').length, color: '#d97706', bg: '#fef3c7', icon: <OngoingIcon /> },
        { label: 'Completed', value: programs.filter(p => p.status === 'COMPLETED').length, color: '#059669', bg: '#d1fae5', icon: <CompletedIcon /> },
        { label: 'Total Enrollments', value: enrollments.length, color: '#7c3aed', bg: '#ede9fe', icon: <PersonIcon /> },
    ];

    return (
        <Box>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                <Box>
                    <Typography variant="h4" fontWeight="bold" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <TrainingIcon sx={{ color: '#2563eb', fontSize: 36 }} /> Training Management
                    </Typography>
                    <Typography variant="body2" color="text.secondary">Manage training programs and employee enrollments</Typography>
                </Box>
                <Button variant="contained" startIcon={<AddIcon />} onClick={() => { resetForms(); setOpenDialog(true); }}
                    sx={{ background: 'linear-gradient(135deg, #2563eb 0%, #1d4ed8 100%)', borderRadius: 2, px: 3 }}>
                    {tab === 0 ? 'Add Program' : 'Enroll Employee'}
                </Button>
            </Box>

            {loading && <LinearProgress sx={{ mb: 2 }} />}

            <Box sx={{ display: 'flex', gap: 2, mb: 3, flexWrap: 'wrap' }}>
                {summaryCards.map((c, i) => (
                    <Card key={i} elevation={1} sx={{ flex: '1 1 180px', minWidth: 160 }}>
                        <CardContent sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                            <Avatar sx={{ bgcolor: c.bg, color: c.color, width: 48, height: 48 }}>{c.icon}</Avatar>
                            <Box>
                                <Typography variant="h5" fontWeight="bold" color={c.color}>{c.value}</Typography>
                                <Typography variant="caption" color="text.secondary">{c.label}</Typography>
                            </Box>
                        </CardContent>
                    </Card>
                ))}
            </Box>

            <Paper elevation={2} sx={{ borderRadius: 3 }}>
                <Tabs value={tab} onChange={(_, v) => setTab(v)} sx={{ borderBottom: 1, borderColor: 'divider', px: 2 }}>
                    <Tab icon={<TrainingIcon />} iconPosition="start" label={`Training Programs (${programs.length})`} />
                    <Tab icon={<EnrollIcon />} iconPosition="start" label={`Enrollments (${enrollments.length})`} />
                </Tabs>

                {/* Programs Tab */}
                <TabPanel value={tab} index={0}>
                    <Box sx={{ px: 2, pb: 2 }}>
                        <TableContainer>
                            <Table>
                                <TableHead>
                                    <TableRow sx={{ bgcolor: '#eff6ff' }}>
                                        {['Title', 'Category', 'Description', 'Start Date', 'End Date', 'Status', 'Actions'].map(h => (
                                            <TableCell key={h} sx={{ fontWeight: 700, color: '#1e40af' }}>{h}</TableCell>
                                        ))}
                                    </TableRow>
                                </TableHead>
                                <TableBody>
                                    {programs.length === 0 ? (
                                        <TableRow><TableCell colSpan={7} align="center" sx={{ py: 6 }}>
                                            <TrainingIcon sx={{ fontSize: 48, color: 'grey.300' }} />
                                            <Typography color="text.secondary" sx={{ mt: 1 }}>No training programs. Click "Add Program" to get started.</Typography>
                                        </TableCell></TableRow>
                                    ) : programs.map(p => (
                                        <TableRow key={p.id} hover>
                                            <TableCell><Typography fontWeight={600}>{p.title}</Typography></TableCell>
                                            <TableCell><Chip label={p.category || 'General'} size="small" variant="outlined" /></TableCell>
                                            <TableCell><Typography variant="body2" noWrap sx={{ maxWidth: 200 }}>{p.description || '-'}</Typography></TableCell>
                                            <TableCell>{p.start_date ? new Date(p.start_date).toLocaleDateString('en-IN') : '-'}</TableCell>
                                            <TableCell>{p.end_date ? new Date(p.end_date).toLocaleDateString('en-IN') : '-'}</TableCell>
                                            <TableCell><Chip label={p.status || 'SCHEDULED'} size="small" color={trainingStatusColors[p.status] || 'default'} /></TableCell>
                                            <TableCell>
                                                <Tooltip title="Edit"><IconButton size="small" color="primary" onClick={() => { setEditingItem(p); setProgramForm({ title: p.title, description: p.description || '', category: p.category || '', start_date: p.start_date?.split('T')[0] || '', end_date: p.end_date?.split('T')[0] || '', status: p.status || 'SCHEDULED' }); setOpenDialog(true); }}><EditIcon fontSize="small" /></IconButton></Tooltip>
                                                <Tooltip title="Delete"><IconButton size="small" color="error" onClick={() => setDeleteDialog({ open: true, id: p.id, type: 'program' })}><DeleteIcon fontSize="small" /></IconButton></Tooltip>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </TableContainer>
                    </Box>
                </TabPanel>

                {/* Enrollments Tab */}
                <TabPanel value={tab} index={1}>
                    <Box sx={{ px: 2, pb: 2 }}>
                        <TableContainer>
                            <Table>
                                <TableHead>
                                    <TableRow sx={{ bgcolor: '#f5f3ff' }}>
                                        {['Employee', 'Training Program', 'Enrollment Date', 'Status', 'Actions'].map(h => (
                                            <TableCell key={h} sx={{ fontWeight: 700, color: '#5b21b6' }}>{h}</TableCell>
                                        ))}
                                    </TableRow>
                                </TableHead>
                                <TableBody>
                                    {enrollments.length === 0 ? (
                                        <TableRow><TableCell colSpan={5} align="center" sx={{ py: 6 }}>
                                            <EnrollIcon sx={{ fontSize: 48, color: 'grey.300' }} />
                                            <Typography color="text.secondary" sx={{ mt: 1 }}>No enrollments yet.</Typography>
                                        </TableCell></TableRow>
                                    ) : enrollments.map(e => (
                                        <TableRow key={e.id} hover>
                                            <TableCell>
                                                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                                                    <Avatar sx={{ width: 32, height: 32, bgcolor: '#7c3aed', fontSize: 12 }}>
                                                        {(e.employee_name || 'E').charAt(0)}
                                                    </Avatar>
                                                    <Box>
                                                        <Typography variant="body2" fontWeight={600}>{e.employee_name || `Employee #${e.employee_id}`}</Typography>
                                                        <Typography variant="caption" color="text.secondary">{e.emp_code}</Typography>
                                                    </Box>
                                                </Box>
                                            </TableCell>
                                            <TableCell>
                                                <Typography variant="body2" fontWeight={600}>{e.training_title || e.program_title || `Program #${e.training_program_id}`}</Typography>
                                                <Typography variant="caption" color="text.secondary">{e.category}</Typography>
                                            </TableCell>
                                            <TableCell>{e.created_at ? new Date(e.created_at).toLocaleDateString('en-IN') : '-'}</TableCell>
                                            <TableCell><Chip label={e.status} size="small" color={enrollmentStatusColors[e.status] || 'default'} /></TableCell>
                                            <TableCell>
                                                <Tooltip title="Update Status"><IconButton size="small" color="primary" onClick={() => { setEditingItem(e); setEnrollForm({ employee_id: e.employee_id, training_program_id: e.training_program_id, status: e.status }); setOpenDialog(true); }}><EditIcon fontSize="small" /></IconButton></Tooltip>
                                                <Tooltip title="Delete"><IconButton size="small" color="error" onClick={() => setDeleteDialog({ open: true, id: e.id, type: 'enrollment' })}><DeleteIcon fontSize="small" /></IconButton></Tooltip>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </TableContainer>
                    </Box>
                </TabPanel>
            </Paper>

            {/* Program Dialog */}
            {tab === 0 && (
                <Dialog open={openDialog} onClose={() => { setOpenDialog(false); resetForms(); }} maxWidth="sm" fullWidth>
                    <DialogTitle sx={{ background: 'linear-gradient(135deg, #2563eb, #1d4ed8)', color: 'white', display: 'flex', justifyContent: 'space-between' }}>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}><TrainingIcon /> {editingItem ? 'Edit Training Program' : 'Create Training Program'}</Box>
                        <IconButton onClick={() => { setOpenDialog(false); resetForms(); }} sx={{ color: 'white' }}><CloseIcon /></IconButton>
                    </DialogTitle>
                    <DialogContent sx={{ pt: 3 }}>
                        <Grid container spacing={2}>
                            <Grid size={12}><TextField fullWidth required label="Training Title" value={programForm.title} onChange={e => setProgramForm(p => ({ ...p, title: e.target.value }))} placeholder="e.g. Advanced Excel Training" /></Grid>
                            <Grid size={{ xs: 12, md: 6 }}><FormControl fullWidth><InputLabel>Category</InputLabel><Select value={programForm.category} label="Category" onChange={e => setProgramForm(p => ({ ...p, category: e.target.value }))}>{trainingCategories.map(c => <MenuItem key={c} value={c}>{c}</MenuItem>)}</Select></FormControl></Grid>
                            <Grid size={{ xs: 12, md: 6 }}><FormControl fullWidth><InputLabel>Status</InputLabel><Select value={programForm.status} label="Status" onChange={e => setProgramForm(p => ({ ...p, status: e.target.value }))}><MenuItem value="DRAFT">Draft</MenuItem><MenuItem value="SCHEDULED">Scheduled</MenuItem><MenuItem value="ONGOING">Ongoing</MenuItem><MenuItem value="COMPLETED">Completed</MenuItem><MenuItem value="CANCELLED">Cancelled</MenuItem></Select></FormControl></Grid>
                            <Grid size={{ xs: 12, md: 6 }}><TextField fullWidth required label="Start Date" type="date" value={programForm.start_date} onChange={e => setProgramForm(p => ({ ...p, start_date: e.target.value }))} InputLabelProps={{ shrink: true }} /></Grid>
                            <Grid size={{ xs: 12, md: 6 }}><TextField fullWidth label="End Date" type="date" value={programForm.end_date} onChange={e => setProgramForm(p => ({ ...p, end_date: e.target.value }))} InputLabelProps={{ shrink: true }} /></Grid>
                            <Grid size={12}><TextField fullWidth multiline rows={3} label="Description" value={programForm.description} onChange={e => setProgramForm(p => ({ ...p, description: e.target.value }))} placeholder="Describe the training objectives and content..." /></Grid>
                        </Grid>
                    </DialogContent>
                    <DialogActions sx={{ p: 2, gap: 1 }}>
                        <Button variant="outlined" onClick={() => { setOpenDialog(false); resetForms(); }}>Cancel</Button>
                        <Button variant="contained" onClick={handleSaveProgram} sx={{ background: 'linear-gradient(135deg, #2563eb, #1d4ed8)' }}>
                            {editingItem ? 'Update Program' : 'Create Program'}
                        </Button>
                    </DialogActions>
                </Dialog>
            )}

            {/* Enrollment Dialog */}
            {tab === 1 && (
                <Dialog open={openDialog} onClose={() => { setOpenDialog(false); resetForms(); }} maxWidth="sm" fullWidth>
                    <DialogTitle sx={{ background: 'linear-gradient(135deg, #7c3aed, #5b21b6)', color: 'white', display: 'flex', justifyContent: 'space-between' }}>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}><EnrollIcon /> {editingItem ? 'Update Enrollment' : 'Enroll Employee'}</Box>
                        <IconButton onClick={() => { setOpenDialog(false); resetForms(); }} sx={{ color: 'white' }}><CloseIcon /></IconButton>
                    </DialogTitle>
                    <DialogContent sx={{ pt: 3 }}>
                        <Grid container spacing={2}>
                            <Grid size={12}><FormControl fullWidth required><InputLabel>Employee</InputLabel><Select value={enrollForm.employee_id} label="Employee" onChange={e => setEnrollForm(p => ({ ...p, employee_id: e.target.value }))}>{employees.map(e => <MenuItem key={e.id} value={e.id}>{e.firstName} {e.lastName} ({e.employeeId})</MenuItem>)}</Select></FormControl></Grid>
                            <Grid size={12}><FormControl fullWidth required><InputLabel>Training Program</InputLabel><Select value={enrollForm.training_program_id} label="Training Program" onChange={e => setEnrollForm(p => ({ ...p, training_program_id: e.target.value }))}>{programs.map(p => <MenuItem key={p.id} value={p.id}>{p.title} {p.status && `(${p.status})`}</MenuItem>)}</Select></FormControl></Grid>
                            <Grid size={12}><FormControl fullWidth><InputLabel>Enrollment Status</InputLabel><Select value={enrollForm.status} label="Enrollment Status" onChange={e => setEnrollForm(p => ({ ...p, status: e.target.value }))}><MenuItem value="ENROLLED">Enrolled</MenuItem><MenuItem value="IN_PROGRESS">In Progress</MenuItem><MenuItem value="COMPLETED">Completed</MenuItem></Select></FormControl></Grid>
                        </Grid>
                    </DialogContent>
                    <DialogActions sx={{ p: 2, gap: 1 }}>
                        <Button variant="outlined" onClick={() => { setOpenDialog(false); resetForms(); }}>Cancel</Button>
                        <Button variant="contained" onClick={handleSaveEnrollment} sx={{ background: 'linear-gradient(135deg, #7c3aed, #5b21b6)' }}>
                            {editingItem ? 'Update' : 'Enroll'}
                        </Button>
                    </DialogActions>
                </Dialog>
            )}

            {/* Delete Dialog */}
            <Dialog open={deleteDialog.open} onClose={() => setDeleteDialog({ open: false, id: 0, type: '' })}>
                <DialogTitle>Confirm Delete</DialogTitle>
                <DialogContent><Typography>Are you sure you want to delete this {deleteDialog.type}?</Typography></DialogContent>
                <DialogActions>
                    <Button onClick={() => setDeleteDialog({ open: false, id: 0, type: '' })}>Cancel</Button>
                    <Button color="error" variant="contained" onClick={handleDelete}>Delete</Button>
                </DialogActions>
            </Dialog>

            <Snackbar open={snackbar.open} autoHideDuration={4000} onClose={() => setSnackbar(p => ({ ...p, open: false }))} anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}>
                <Alert severity={snackbar.severity} onClose={() => setSnackbar(p => ({ ...p, open: false }))} variant="filled">{snackbar.message}</Alert>
            </Snackbar>
        </Box>
    );
};

export default TrainingManagementForm;

// @ts-nocheck
import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Card,
  CardContent,
  Chip,
  Alert,
  Snackbar,
  Divider,
  Switch,
  FormControlLabel,
} from '@mui/material';
import {
  Save as SaveIcon,
  Cancel as CancelIcon,
  School as TrainingIcon,
  Person as TrainerIcon,
  Schedule as ScheduleIcon,
} from '@mui/icons-material';
import { useNavigate, useParams } from 'react-router-dom';

interface TrainingProgram {
  id?: number;
  title: string;
  description: string;
  category: string;
  type: 'INTERNAL' | 'EXTERNAL' | 'ONLINE' | 'WORKSHOP';
  duration: number; // in hours
  maxParticipants: number;
  trainerId?: number;
  trainerName?: string;
  externalTrainer?: string;
  startDate: string;
  endDate: string;
  venue: string;
  prerequisites?: string;
  objectives: string;
  materials?: string;
  cost: number;
  currency: string;
  status: 'DRAFT' | 'SCHEDULED' | 'ONGOING' | 'COMPLETED' | 'CANCELLED';
  isMandatory: boolean;
  certificateProvided: boolean;
  skillsToGain: string[];
  targetAudience: string;
  isActive: boolean;
}

const trainingCategories = [
  'Technical Skills',
  'Soft Skills',
  'Leadership',
  'Compliance',
  'Safety',
  'Product Knowledge',
  'Process Training',
  'Orientation',
  'Professional Development',
  'Other'
];

const TrainingProgramForm: React.FC = () => {
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);

  const [loading, setLoading] = useState(false);
  const [trainers, setTrainers] = useState<any[]>([]);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'success' as 'success' | 'error' | 'warning'
  });

  const [trainingProgram, setTrainingProgram] = useState<TrainingProgram>({
    title: '',
    description: '',
    category: '',
    type: 'INTERNAL',
    duration: 0,
    maxParticipants: 20,
    startDate: '',
    endDate: '',
    venue: '',
    objectives: '',
    cost: 0,
    currency: 'INR',
    status: 'DRAFT',
    isMandatory: false,
    certificateProvided: false,
    skillsToGain: [],
    targetAudience: '',
    isActive: true,
  });

  const [newSkill, setNewSkill] = useState('');

  useEffect(() => {
    loadTrainers();
    if (isEdit && id) {
      loadTrainingProgram(parseInt(id));
    }
  }, [isEdit, id]);

  const loadTrainers = async () => {
    try {
      // In real app: const response = await apiService.getTrainers();
      // Mock data
      setTrainers([
        { id: 1, name: 'John Smith', expertise: 'Technical Training' },
        { id: 2, name: 'Sarah Johnson', expertise: 'Soft Skills' },
        { id: 3, name: 'Mike Wilson', expertise: 'Leadership' },
      ]);
    } catch (error) {
      console.error('Error loading trainers:', error);
    }
  };

  const loadTrainingProgram = async (programId: number) => {
    try {
      setLoading(true);
      // In real app: const response = await apiService.getTrainingProgramById(programId);
      // Mock data for demonstration
    } catch (error) {
      console.error('Error loading training program:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field: keyof TrainingProgram) => (
    event: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement> | any
  ) => {
    const value = event.target.type === 'checkbox' ? event.target.checked : event.target.value;
    setTrainingProgram(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const addSkill = () => {
    if (newSkill.trim() && !trainingProgram.skillsToGain.includes(newSkill.trim())) {
      setTrainingProgram(prev => ({
        ...prev,
        skillsToGain: [...prev.skillsToGain, newSkill.trim()]
      }));
      setNewSkill('');
    }
  };

  const removeSkill = (skillToRemove: string) => {
    setTrainingProgram(prev => ({
      ...prev,
      skillsToGain: prev.skillsToGain.filter(skill => skill !== skillToRemove)
    }));
  };

  const handleSkillKeyPress = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      addSkill();
    }
  };

  const validateForm = () => {
    const errors: string[] = [];

    if (!trainingProgram.title.trim()) errors.push('Training Title is required');
    if (!trainingProgram.description.trim()) errors.push('Description is required');
    if (!trainingProgram.category) errors.push('Category is required');
    if (!trainingProgram.startDate) errors.push('Start Date is required');
    if (!trainingProgram.endDate) errors.push('End Date is required');
    if (!trainingProgram.venue.trim()) errors.push('Venue is required');
    if (!trainingProgram.objectives.trim()) errors.push('Objectives are required');
    if (!trainingProgram.targetAudience.trim()) errors.push('Target Audience is required');
    if (trainingProgram.duration <= 0) errors.push('Duration must be greater than 0');
    if (trainingProgram.maxParticipants <= 0) errors.push('Max Participants must be greater than 0');

    if (trainingProgram.startDate && trainingProgram.endDate) {
      if (new Date(trainingProgram.startDate) > new Date(trainingProgram.endDate)) {
        errors.push('End Date must be after Start Date');
      }
    }

    if (trainingProgram.type === 'INTERNAL' && !trainingProgram.trainerId) {
      errors.push('Internal Trainer is required for internal training');
    }

    if (trainingProgram.type === 'EXTERNAL' && !trainingProgram.externalTrainer?.trim()) {
      errors.push('External Trainer name is required for external training');
    }

    return errors;
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();

    const validationErrors = validateForm();
    if (validationErrors.length > 0) {
      setSnackbar({
        open: true,
        message: 'Please fix the following errors:\n' + validationErrors.join('\n'),
        severity: 'error'
      });
      return;
    }

    try {
      setLoading(true);
      if (isEdit && id) {
        // await apiService.updateTrainingProgram(parseInt(id), trainingProgram);
        setSnackbar({ open: true, message: 'Training program updated successfully!', severity: 'success' });
      } else {
        // await apiService.createTrainingProgram(trainingProgram);
        setSnackbar({ open: true, message: 'Training program created successfully!', severity: 'success' });
      }
      setTimeout(() => navigate('/training/programs'), 1500);
    } catch (error) {
      console.error('Error saving training program:', error);
      setSnackbar({ open: true, message: 'Error saving training program. Please try again.', severity: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate('/training/programs');
  };

  return (
    <Box>
      <Typography variant="h4" component="h1" sx={{ fontWeight: 'bold', mb: 1 }}>
        {isEdit ? 'Edit Training Program' : 'Create Training Program'}
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        Create and manage training programs for employee development.
      </Typography>
      <Paper elevation={2} sx={{ p: 3 }}>
        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            {/* Basic Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <TrainingIcon />
                Basic Information
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 8
              }}>
              <TextField
                fullWidth
                label="Training Title"
                required
                value={trainingProgram.title}
                onChange={handleInputChange('title')}
                placeholder="e.g., Advanced React Development Workshop"
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <FormControl fullWidth required>
                <InputLabel>Category</InputLabel>
                <Select
                  value={trainingProgram.category}
                  label="Category"
                  onChange={handleInputChange('category')}
                >
                  {trainingCategories.map((category) => (
                    <MenuItem key={category} value={category}>
                      {category}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>

            <Grid size={12}>
              <TextField
                fullWidth
                label="Description"
                multiline
                rows={3}
                required
                value={trainingProgram.description}
                onChange={handleInputChange('description')}
                placeholder="Provide a detailed description of the training program..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <FormControl fullWidth required>
                <InputLabel>Training Type</InputLabel>
                <Select
                  value={trainingProgram.type}
                  label="Training Type"
                  onChange={handleInputChange('type')}
                >
                  <MenuItem value="INTERNAL">Internal</MenuItem>
                  <MenuItem value="EXTERNAL">External</MenuItem>
                  <MenuItem value="ONLINE">Online</MenuItem>
                  <MenuItem value="WORKSHOP">Workshop</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <TextField
                fullWidth
                label="Duration (Hours)"
                type="number"
                required
                value={trainingProgram.duration}
                onChange={handleInputChange('duration')}
                InputProps={{ inputProps: { min: 0.5, step: 0.5 } }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <TextField
                fullWidth
                label="Max Participants"
                type="number"
                required
                value={trainingProgram.maxParticipants}
                onChange={handleInputChange('maxParticipants')}
                InputProps={{ inputProps: { min: 1 } }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 3
              }}>
              <FormControl fullWidth>
                <InputLabel>Status</InputLabel>
                <Select
                  value={trainingProgram.status}
                  label="Status"
                  onChange={handleInputChange('status')}
                >
                  <MenuItem value="DRAFT">Draft</MenuItem>
                  <MenuItem value="SCHEDULED">Scheduled</MenuItem>
                  <MenuItem value="ONGOING">Ongoing</MenuItem>
                  <MenuItem value="COMPLETED">Completed</MenuItem>
                  <MenuItem value="CANCELLED">Cancelled</MenuItem>
                </Select>
              </FormControl>
            </Grid>

            {/* Trainer Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 2 }}>
                <TrainerIcon />
                Trainer Information
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            {trainingProgram.type === 'INTERNAL' && (
              <Grid
                size={{
                  xs: 12,
                  md: 6
                }}>
                <FormControl fullWidth required>
                  <InputLabel>Internal Trainer</InputLabel>
                  <Select
                    value={trainingProgram.trainerId || ''}
                    label="Internal Trainer"
                    onChange={handleInputChange('trainerId')}
                  >
                    {trainers.map((trainer) => (
                      <MenuItem key={trainer.id} value={trainer.id}>
                        {trainer.name} - {trainer.expertise}
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
              </Grid>
            )}

            {trainingProgram.type === 'EXTERNAL' && (
              <Grid
                size={{
                  xs: 12,
                  md: 6
                }}>
                <TextField
                  fullWidth
                  label="External Trainer/Organization"
                  required
                  value={trainingProgram.externalTrainer || ''}
                  onChange={handleInputChange('externalTrainer')}
                  placeholder="Enter trainer name or organization"
                />
              </Grid>
            )}

            {/* Schedule Information */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 2 }}>
                <ScheduleIcon />
                Schedule & Venue
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Start Date"
                type="date"
                required
                value={trainingProgram.startDate}
                onChange={handleInputChange('startDate')}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="End Date"
                type="date"
                required
                value={trainingProgram.endDate}
                onChange={handleInputChange('endDate')}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Venue"
                required
                value={trainingProgram.venue}
                onChange={handleInputChange('venue')}
                placeholder="e.g., Conference Room A, Online Platform"
              />
            </Grid>

            {/* Training Details */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Training Details
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Learning Objectives"
                multiline
                rows={4}
                required
                value={trainingProgram.objectives}
                onChange={handleInputChange('objectives')}
                placeholder="List the key learning objectives..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Target Audience"
                multiline
                rows={4}
                required
                value={trainingProgram.targetAudience}
                onChange={handleInputChange('targetAudience')}
                placeholder="Describe the target audience for this training..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Prerequisites"
                multiline
                rows={3}
                value={trainingProgram.prerequisites || ''}
                onChange={handleInputChange('prerequisites')}
                placeholder="List any prerequisites or requirements..."
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 6
              }}>
              <TextField
                fullWidth
                label="Training Materials"
                multiline
                rows={3}
                value={trainingProgram.materials || ''}
                onChange={handleInputChange('materials')}
                placeholder="List materials, resources, or tools needed..."
              />
            </Grid>

            {/* Skills to Gain */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Skills to Gain
              </Typography>
              <TextField
                fullWidth
                label="Add Skill"
                value={newSkill}
                onChange={(e) => setNewSkill(e.target.value)}
                onKeyPress={handleSkillKeyPress}
                placeholder="Type a skill and press Enter"
                helperText="Press Enter to add skills"
              />
              <Box sx={{ mt: 1, display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                {trainingProgram.skillsToGain.map((skill, index) => (
                  <Chip
                    key={index}
                    label={skill}
                    onDelete={() => removeSkill(skill)}
                    size="small"
                  />
                ))}
              </Box>
            </Grid>

            {/* Cost & Settings */}
            <Grid size={12}>
              <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
                Cost & Settings
              </Typography>
              <Divider sx={{ mb: 2 }} />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 4
              }}>
              <TextField
                fullWidth
                label="Training Cost"
                type="number"
                value={trainingProgram.cost}
                onChange={handleInputChange('cost')}
                InputProps={{
                  startAdornment: '₹',
                  inputProps: { min: 0 }
                }}
              />
            </Grid>

            <Grid
              size={{
                xs: 12,
                md: 8
              }}>
              <Box sx={{ display: 'flex', gap: 3, alignItems: 'center' }}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={trainingProgram.isMandatory}
                      onChange={handleInputChange('isMandatory')}
                    />
                  }
                  label="Mandatory Training"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={trainingProgram.certificateProvided}
                      onChange={handleInputChange('certificateProvided')}
                    />
                  }
                  label="Certificate Provided"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={trainingProgram.isActive}
                      onChange={handleInputChange('isActive')}
                    />
                  }
                  label="Active"
                />
              </Box>
            </Grid>

            <Grid size={12}>
              <Box sx={{ display: 'flex', justifyContent: 'flex-end', gap: 2, mt: 3 }}>
                <Button
                  variant="outlined"
                  startIcon={<CancelIcon />}
                  onClick={handleCancel}
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  variant="contained"
                  startIcon={<SaveIcon />}
                  disabled={loading}
                >
                  {loading ? 'Saving...' : isEdit ? 'Update Program' : 'Create Program'}
                </Button>
              </Box>
            </Grid>
          </Grid>
        </form>
      </Paper>
      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
      >
        <Alert
          severity={snackbar.severity}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
          variant="filled"
          sx={{ whiteSpace: 'pre-line' }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default TrainingProgramForm;

